type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInner(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  // Undefined source never overwrites — treat as "no value provided"
  if (source === undefined) return target;

  // Guard against circular references in source graph
  if (source !== null && typeof source === "object") {
    if (seen.has(source)) return seen.get(source);
  }

  // Both arrays → concatenate (source appended after target)
  if (Array.isArray(target) && Array.isArray(source)) {
    const result = [...target, ...source];
    seen.set(source, result);
    return result;
  }

  // Both plain objects → recursive merge
  if (isPlainObject(target) && isPlainObject(source)) {
    // Shallow-copy target first so we never mutate the original
    const result: PlainObject = Object.assign({}, target);
    // Register before recursing so circular refs resolve to this object
    seen.set(source, result);

    for (const key of Object.keys(source)) {
      // Harden against prototype-pollution attacks
      if (key === "__proto__" || key === "constructor" || key === "prototype") {
        continue;
      }
      result[key] = mergeInner(target[key], source[key], seen);
    }

    return result;
  }

  // Scalar, Date, RegExp, mismatched types, null, etc. → source wins
  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: 'target' must be a plain object (received ${
        target === null ? "null" : typeof target
      })`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: 'source' must be a plain object (received ${
        source === null ? "null" : typeof source
      })`
    );
  }

  return mergeInner(target, source, new WeakMap()) as T & S;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    !(value instanceof Date) &&
    !(value instanceof RegExp) &&
    !(value instanceof Map) &&
    !(value instanceof Set)
  );
}

function flattenObject(
  obj: PlainObject,
  prefix = "",
  ancestry = new WeakSet<object>()
): PlainObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(`flattenObject expects a plain object, received: ${obj === null ? "null" : typeof obj}`);
  }

  if (ancestry.has(obj)) {
    throw new Error(`Circular reference detected at key: "${prefix}"`);
  }

  ancestry.add(obj);

  const result: PlainObject = {};
  const keys = Object.keys(obj);

  for (const key of keys) {
    if (key === "") continue; // skip empty string keys — unpredictable dot-notation behavior

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      const nested = flattenObject(value, fullKey, ancestry);
      for (const nestedKey of Object.keys(nested)) {
        result[nestedKey] = nested[nestedKey];
      }
    } else {
      result[fullKey] = value;
    }
  }

  ancestry.delete(obj); // allow the same reference on sibling paths (diamond shapes)

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const mergeValue = (target: unknown, source: unknown): unknown => {
  if (isPlainObject(target) && isPlainObject(source)) {
    return deepMerge(target, source);
  }
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }
  return source;
};

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError("Both target and source must be plain objects");
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    result[key] = Object.prototype.hasOwnProperty.call(target, key)
      ? mergeValue(target[key], source[key])
      : source[key];
  }

  return result;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldRange = { min: number; max: number };

const FIELD_RANGES: Record<keyof CronResult, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} out of range [${range.min}-${range.max}] in field "${context}"`
    );
  }
}

function parseSegment(segment: string, range: FieldRange, fieldName: string): number[] {
  // Wildcard
  if (segment === "*") {
    return Array.from({ length: range.max - range.min + 1 }, (_, i) => range.min + i);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let from = range.min;
    let to = range.max;

    if (left !== "*") {
      if (left.includes("-")) {
        const [startStr, endStr] = left.split("-");
        from = parseInt(startStr, 10);
        to   = parseInt(endStr, 10);
        if (isNaN(from) || isNaN(to)) {
          throw new SyntaxError(`Invalid range "${left}" in field "${fieldName}"`);
        }
        assertInRange(from, range, fieldName);
        assertInRange(to, range, fieldName);
        if (from > to) {
          throw new RangeError(`Range start ${from} > end ${to} in field "${fieldName}"`);
        }
      } else {
        from = parseInt(left, 10);
        if (isNaN(from)) {
          throw new SyntaxError(`Invalid segment "${segment}" in field "${fieldName}"`);
        }
        assertInRange(from, range, fieldName);
        to = range.max;
      }
    }

    const values: number[] = [];
    for (let v = from; v <= to; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(start, range, fieldName);
    assertInRange(end,   range, fieldName);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    }

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, range, fieldName);
  return [value];
}

function parseField(expr: string, range: FieldRange, fieldName: string): number[] {
  const segments = expr.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field "${fieldName}"`);
    }
    for (const v of parseSegment(trimmed, range, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, FIELD_RANGES.minute,     "minute"),
    hour:       parseField(hourExpr,   FIELD_RANGES.hour,       "hour"),
    dayOfMonth: parseField(domExpr,    FIELD_RANGES.dayOfMonth, "dayOfMonth"),
    month:      parseField(monthExpr,  FIELD_RANGES.month,      "month"),
    dayOfWeek:  parseField(dowExpr,    FIELD_RANGES.dayOfWeek,  "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function expandWildcard(field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  return Array.from({ length: max - min + 1 }, (_, i) => i + min);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      [rangeMin, rangeMax] = parseRange(rangePart, field);
    } else {
      rangeMin = parseInt(rangePart, 10);
      if (isNaN(rangeMin)) {
        throw new SyntaxError(`Invalid step expression "${segment}" in field "${field}"`);
      }
      assertInRange(rangeMin, field);
      rangeMax = max;
    }

    const result: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      result.push(v);
    }
    return result;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [rangeMin, rangeMax] = parseRange(segment, field);
    return Array.from({ length: rangeMax - rangeMin + 1 }, (_, i) => i + rangeMin);
  }

  // Wildcard
  if (segment === "*") {
    return expandWildcard(field);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, field);
  return [value];
}

function parseRange(rangePart: string, field: CronField): [number, number] {
  const parts = rangePart.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(`Invalid range "${rangePart}" in field "${field}"`);
  }
  const rangeMin = parseInt(parts[0], 10);
  const rangeMax = parseInt(parts[1], 10);
  if (isNaN(rangeMin) || isNaN(rangeMax)) {
    throw new SyntaxError(`Invalid range "${rangePart}" in field "${field}"`);
  }
  assertInRange(rangeMin, field);
  assertInRange(rangeMax, field);
  if (rangeMin > rangeMax) {
    throw new RangeError(
      `Range start ${rangeMin} exceeds end ${rangeMax} in field "${field}"`
    );
  }
  return [rangeMin, rangeMax];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const v of parseSegment(trimmed, field)) {
      // Normalize dayOfWeek: both 0 and 7 represent Sunday
      if (field === "dayOfWeek" && v === 7) {
        valueSet.add(0);
      } else {
        valueSet.add(v);
      }
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length} in expression "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flatten(
  obj: NestedObject | Array<unknown>,
  prefix: string,
  result: FlatObject
): void {
  if (Array.isArray(obj)) {
    obj.forEach((item, index) => {
      const key = `${prefix}[${index}]`;
      if (item !== null && typeof item === "object") {
        flatten(item as NestedObject, key, result);
      } else {
        result[key] = item as Primitive;
      }
    });
  } else {
    for (const [k, value] of Object.entries(obj)) {
      const key = prefix ? `${prefix}.${k}` : k;
      if (value === null || value === undefined) {
        result[key] = value;
      } else if (Array.isArray(value)) {
        flatten(value, key, result);
      } else if (typeof value === "object") {
        const entries = Object.keys(value as object);
        if (entries.length === 0) {
          result[key] = undefined;
        } else {
          flatten(value as NestedObject, key, result);
        }
      } else {
        result[key] = value as Primitive;
      }
    }
  }
}

export default function flattenObject(
  obj: NestedObject,
  prefix: string = ""
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    throw new TypeError("Input must be a plain object");
  }
  const result: FlatObject = {};
  flatten(obj, prefix, result);
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  return source !== undefined ? source : target;
}

export default deepMerge;

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof ParsedCron;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  6 },
] as const;

const DIGITS_RE = /^\d+$/;

function buildRange(start: number, end: number, step = 1): number[] {
  if (step <= 0) throw new RangeError(`Step must be a positive integer, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
}

function parsePositiveInt(raw: string, context: string): number {
  if (!DIGITS_RE.test(raw)) {
    throw new SyntaxError(`Expected a non-negative integer in ${context}, got "${raw}"`);
  }
  const n = parseInt(raw, 10);
  if (isNaN(n)) throw new SyntaxError(`Could not parse integer in ${context}: "${raw}"`);
  return n;
}

function assertInBounds(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of range [${config.min}, ${config.max}] ` +
      `for field "${config.name}" (${context})`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max, name } = config;

  // ── Step: "*/n" or "base/n" ──────────────────────────────────────────────
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${segment}" in field "${name}"`);
    }
    const [baseRaw, stepRaw] = slashParts;
    const step = parsePositiveInt(stepRaw, `step of field "${name}"`);
    if (step === 0) throw new RangeError(`Step value cannot be 0 in field "${name}"`);

    let rangeStart: number;
    let rangeEnd: number;

    if (baseRaw === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (baseRaw.includes("-")) {
      const rangeParts = baseRaw.split("-");
      if (rangeParts.length !== 2) {
        throw new SyntaxError(`Invalid range in step base "${baseRaw}" for field "${name}"`);
      }
      rangeStart = parsePositiveInt(rangeParts[0], `range start in field "${name}"`);
      rangeEnd   = parsePositiveInt(rangeParts[1], `range end in field "${name}"`);
    } else {
      rangeStart = parsePositiveInt(baseRaw, `step base in field "${name}"`);
      rangeEnd = max;
    }

    assertInBounds(rangeStart, config, "step range start");
    assertInBounds(rangeEnd,   config, "step range end");
    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start ${rangeStart} exceeds end ${rangeEnd} in field "${name}"`
      );
    }
    return buildRange(rangeStart, rangeEnd, step);
  }

  // ── Wildcard ─────────────────────────────────────────────────────────────
  if (segment === "*") {
    return buildRange(min, max);
  }

  // ── Range: "a-b" ─────────────────────────────────────────────────────────
  if (segment.includes("-")) {
    const rangeParts = segment.split("-");
    if (rangeParts.length !== 2) {
      throw new SyntaxError(`Invalid range expression "${segment}" in field "${name}"`);
    }
    const start = parsePositiveInt(rangeParts[0], `range start in field "${name}"`);
    const end   = parsePositiveInt(rangeParts[1], `range end in field "${name}"`);
    assertInBounds(start, config, "range start");
    assertInBounds(end,   config, "range end");
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field "${name}"`
      );
    }
    return buildRange(start, end);
  }

  // ── Single number ─────────────────────────────────────────────────────────
  const num = parsePositiveInt(segment, `value in field "${name}"`);
  assertInBounds(num, config, "single value");
  return [num];
}

function parseField(expression: string, config: FieldConfig): number[] {
  if (!expression || expression.trim() === "") {
    throw new SyntaxError(`Empty expression for field "${config.name}"`);
  }

  // ── Comma-separated list ─────────────────────────────────────────────────
  if (expression.includes(",")) {
    const parts = expression.split(",");
    if (parts.some(p => p.trim() === "")) {
      throw new SyntaxError(
        `Empty item in comma-separated list for field "${config.name}": "${expression}"`
      );
    }
    const seen = new Set<number>();
    for (const part of parts) {
      for (const v of parseSegment(part.trim(), config)) seen.add(v);
    }
    return [...seen].sort((a, b) => a - b);
  }

  return parseSegment(expression.trim(), config);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Guard against non-ASCII or shell-injection characters early
  if (/[^\x20-\x7E]/.test(trimmed)) {
    throw new SyntaxError("Cron expression contains non-printable or non-ASCII characters");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`
    );
  }

  const result = {} as ParsedCron;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    const parsed = parseField(fields[i], config);
    if (parsed.length === 0) {
      throw new RangeError(`Field "${config.name}" resolved to an empty value set`);
    }
    result[config.name] = parsed;
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseField(expr: string, field: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step in "${expr}"`);
    const values: number[] = [];
    for (let v = min; v <= max; v += step) values.push(v);
    return values;
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step in "${expr}"`);

    let start: number;
    let end: number;

    if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
      if (isNaN(s) || isNaN(e)) throw new SyntaxError(`Invalid range in "${expr}"`);
      assertInRange(s, min, max, field);
      assertInRange(e, min, max, field);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new SyntaxError(`Invalid expression "${expr}"`);
      assertInRange(start, min, max, field);
      end = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  if (expr.includes("-")) {
    const [s, e] = expr.split("-").map((n) => parseInt(n, 10));
    if (isNaN(s) || isNaN(e)) throw new SyntaxError(`Invalid range "${expr}"`);
    assertInRange(s, min, max, field);
    assertInRange(e, min, max, field);
    return range(s, e);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid value "${expr}" for field "${field}"`);
  assertInRange(value, min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] | unknown };
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  visited = new WeakSet<object>(),
  result: FlatObject = {}
): FlatObject {
  if (input === null || typeof input !== "object") {
    if (prefix !== "") result[prefix] = input;
    return result;
  }

  if (visited.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }
  visited.add(input as object);

  const isArray = Array.isArray(input);
  const isPlain = isPlainObject(input);

  if (!isPlain && !isArray) {
    // Non-plain object instances (Date, RegExp, Map, Set, etc.) — treat as leaf
    if (prefix !== "") result[prefix] = input;
    visited.delete(input as object);
    return result;
  }

  const entries = isArray
    ? (input as unknown[]).map((v, i) => [String(i), v] as [string, unknown])
    : Object.entries(input as Record<string, unknown>);

  if (entries.length === 0) {
    // Preserve empty objects/arrays so callers know the key existed
    if (prefix !== "") result[prefix] = input;
    visited.delete(input as object);
    return result;
  }

  for (const [key, value] of entries) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      // Refuse to flatten dangerous prototype-polluting keys
      continue;
    }

    const nextKey = prefix === "" ? key : `${prefix}.${key}`;

    if (value !== null && typeof value === "object") {
      flattenObject(value, nextKey, visited, result);
    } else {
      result[nextKey] = value;
    }
  }

  visited.delete(input as object);
  return result;
}

export default flattenObject;

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function parseNonNegativeInt(s: string, context: string): number {
  if (!/^\d+$/.test(s)) {
    throw new Error(`Expected a non-negative integer but got "${s}" (${context})`);
  }
  const value = parseInt(s, 10);
  if (!isFinite(value)) {
    throw new Error(`Parsed value is not finite for "${s}" (${context})`);
  }
  return value;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of valid range [${min}, ${max}] (${context})`);
  }
}

function generateRange(start: number, end: number, step = 1): number[] {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(token: string, min: number, max: number, fieldName: string): number[] {
  const context = `field "${fieldName}", segment "${token}"`;

  if (token === '') {
    throw new Error(`Empty segment (${context})`);
  }

  const slashParts = token.split('/');

  if (slashParts.length > 2) {
    throw new Error(`Multiple "/" operators are not allowed (${context})`);
  }

  // Step expression: base/step
  if (slashParts.length === 2) {
    const [basePart, stepStr] = slashParts;

    if (stepStr === '') {
      throw new Error(`Missing step value after "/" (${context})`);
    }

    const step = parseNonNegativeInt(stepStr, context);
    if (step === 0) {
      throw new Error(`Step value cannot be 0 (${context})`);
    }

    if (basePart === '*') {
      return generateRange(min, max, step);
    }

    const dashParts = basePart.split('-');

    if (dashParts.length === 2) {
      const start = parseNonNegativeInt(dashParts[0], context);
      const end = parseNonNegativeInt(dashParts[1], context);
      assertInRange(start, min, max, context);
      assertInRange(end, min, max, context);
      if (start > end) {
        throw new Error(`Range start ${start} cannot be greater than end ${end} (${context})`);
      }
      return generateRange(start, end, step);
    }

    if (dashParts.length === 1) {
      const start = parseNonNegativeInt(basePart, context);
      assertInRange(start, min, max, context);
      return generateRange(start, max, step);
    }

    throw new Error(`Invalid range expression "${basePart}" (${context})`);
  }

  // Wildcard: *
  if (token === '*') {
    return generateRange(min, max);
  }

  const dashParts = token.split('-');

  // Range: N-M
  if (dashParts.length === 2) {
    if (dashParts[0] === '' || dashParts[1] === '') {
      throw new Error(`Malformed range expression "${token}" (${context})`);
    }
    const start = parseNonNegativeInt(dashParts[0], context);
    const end = parseNonNegativeInt(dashParts[1], context);
    assertInRange(start, min, max, context);
    assertInRange(end, min, max, context);
    if (start > end) {
      throw new Error(`Range start ${start} cannot be greater than end ${end} (${context})`);
    }
    return generateRange(start, end);
  }

  // Single value: N
  if (dashParts.length === 1) {
    const value = parseNonNegativeInt(token, context);
    assertInRange(value, min, max, context);
    return [value];
  }

  throw new Error(`Invalid expression "${token}" (${context})`);
}

function parseField(expression: string, min: number, max: number, fieldName: string): number[] {
  if (expression === '') {
    throw new Error(`Empty expression for field "${fieldName}"`);
  }

  const tokens = expression.split(',');
  const valueSet = new Set<number>();

  for (const token of tokens) {
    const trimmed = token.trim();
    if (trimmed === '') {
      throw new Error(
        `Empty token in comma-separated list for field "${fieldName}" — trailing/double commas are not allowed`
      );
    }
    const values = parseSegment(trimmed, min, max, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  if (valueSet.size === 0) {
    throw new Error(`Expression for field "${fieldName}" produced no values`);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== 'string') {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === '') {
    throw new Error('Cron expression must not be empty');
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, 0,  59, 'minute'),
    hour:       parseField(hourExpr,   0,  23, 'hour'),
    dayOfMonth: parseField(domExpr,    1,  31, 'dayOfMonth'),
    month:      parseField(monthExpr,  1,  12, 'month'),
    dayOfWeek:  parseField(dowExpr,    0,   7, 'dayOfWeek'),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

