type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(field: CronField, token: string, reason: string) {
    super(`Invalid cron expression — field "${field}", token "${token}": ${reason}`);
    this.name = "CronParseError";
  }
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) return NaN;
  return value;
}

function range(from: number, to: number): number[] {
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseToken(token: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard: *
  if (token === "*") return range(min, max);

  // Step: */n or start-end/n
  if (token.includes("/")) {
    const [rangeExpr, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0)
      throw new CronParseError(field, token, "step must be a positive integer");

    let base: number[];

    if (rangeExpr === "*") {
      base = range(min, max);
    } else if (rangeExpr.includes("-")) {
      const [fromStr, toStr] = rangeExpr.split("-");
      const from = clamp(parseInt(fromStr, 10), min, max);
      const to   = clamp(parseInt(toStr,   10), min, max);

      if (isNaN(from) || isNaN(to))
        throw new CronParseError(field, token, `range values must be between ${min} and ${max}`);
      if (from > to)
        throw new CronParseError(field, token, "range start must not exceed range end");

      base = range(from, to);
    } else {
      const start = clamp(parseInt(rangeExpr, 10), min, max);
      if (isNaN(start))
        throw new CronParseError(field, token, `start value must be between ${min} and ${max}`);
      base = range(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Range: from-to
  if (token.includes("-")) {
    const [fromStr, toStr] = token.split("-");
    const from = clamp(parseInt(fromStr, 10), min, max);
    const to   = clamp(parseInt(toStr,   10), min, max);

    if (isNaN(from) || isNaN(to))
      throw new CronParseError(field, token, `range values must be between ${min} and ${max}`);
    if (from > to)
      throw new CronParseError(field, token, "range start must not exceed range end");

    return range(from, to);
  }

  // Bare number
  const value = clamp(parseInt(token, 10), min, max);
  if (isNaN(value))
    throw new CronParseError(field, token, `value must be between ${min} and ${max}`);

  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const tokens = expression.split(",");
  const values = new Set<number>();

  for (const token of tokens) {
    if (!token.trim())
      throw new CronParseError(field, expression, "empty token in list");

    for (const v of parseToken(token.trim(), field)) {
      values.add(v);
    }
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || !expression.trim())
    throw new Error("Cron expression must be a non-empty string");

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5)
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );

  return FIELD_ORDER.reduce((acc, field, i) => {
    acc[field] = parseField(fields[i], field);
    return acc;
  }, {} as ParsedCron);
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const rangeArray = (start: number, end: number, step = 1): number[] => {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
};

const clampToRange = (value: number, { min, max }: FieldRange, label: string): number => {
  if (value < min || value > max)
    throw new Error(`Value ${value} out of range [${min}-${max}] for field "${label}"`);
  return value;
};

const parseSegment = (segment: string, range: FieldRange, label: string): number[] => {
  // Wildcard: *
  if (segment === "*") return rangeArray(range.min, range.max);

  // Step with wildcard: */n
  const stepWildcard = segment.match(/^\*\/(\d+)$/);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    return rangeArray(range.min, range.max, step);
  }

  // Range with optional step: a-b or a-b/n
  const rangeStep = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeStep) {
    const start = clampToRange(parseInt(rangeStep[1], 10), range, label);
    const end   = clampToRange(parseInt(rangeStep[2], 10), range, label);
    if (start > end) throw new Error(`Invalid range ${start}-${end} for field "${label}"`);
    const step = rangeStep[3] ? parseInt(rangeStep[3], 10) : 1;
    return rangeArray(start, end, step);
  }

  // Step from a base: a/n
  const baseStep = segment.match(/^(\d+)\/(\d+)$/);
  if (baseStep) {
    const start = clampToRange(parseInt(baseStep[1], 10), range, label);
    const step  = parseInt(baseStep[2], 10);
    return rangeArray(start, range.max, step);
  }

  // Plain number
  const plain = segment.match(/^(\d+)$/);
  if (plain) {
    return [clampToRange(parseInt(plain[1], 10), range, label)];
  }

  throw new Error(`Unrecognised cron segment "${segment}" for field "${label}"`);
};

const parseField = (expr: string, range: FieldRange, label: string): number[] => {
  const values = expr
    .split(",")
    .flatMap((segment) => parseSegment(segment.trim(), range, label));

  const unique = [...new Set(values)].sort((a, b) => a - b);
  return unique;
};

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim())
    throw new Error("Cron expression must be a non-empty string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(`Cron expression must have exactly 5 fields, got ${parts.length}`);

  const entries = FIELD_ORDER.map((field, i) => [
    field,
    parseField(parts[i], FIELD_RANGES[field], field),
  ]) as [CronField, number[]][];

  return Object.fromEntries(entries) as CronResult;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInner(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  if (source === undefined) return target;
  if (source === null) return null;

  if (Array.isArray(source)) {
    return Array.isArray(target) ? [...target, ...source] : [...source];
  }

  if (isPlainObject(source)) {
    const resolvedTarget: PlainObject = isPlainObject(target)
      ? target
      : {};

    if (seen.has(source)) return seen.get(source);

    const result: PlainObject = { ...resolvedTarget };
    seen.set(source, result);

    for (const key of Object.keys(source)) {
      result[key] = mergeInner(resolvedTarget[key], source[key], seen);
    }

    return result;
  }

  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  const seen = new WeakMap<object, unknown>();
  return mergeInner(target, source, seen) as T & S;
}

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  (Object.getPrototypeOf(value) === Object.prototype ||
    Object.getPrototypeOf(value) === null);

const mergeValue = (target: unknown, source: unknown): unknown => {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }
  if (isPlainObject(target) && isPlainObject(source)) {
    return deepMerge(target, source);
  }
  return source;
};

function deepMerge(target: PlainObject, source: PlainObject): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return isPlainObject(source) ? { ...source } : isPlainObject(target) ? { ...target } : {};
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    result[key] = Object.prototype.hasOwnProperty.call(target, key)
      ? mergeValue(target[key], source[key])
      : source[key];
  }

  return result;
}

export default deepMerge;

type Scalar = string | number | boolean | bigint | symbol | null | undefined;
type LeafValue = Scalar | unknown[] | Date | RegExp | ((...args: unknown[]) => unknown);

type FlattenedObject = Record<string, LeafValue>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function _flatten(
  obj: Record<string, unknown>,
  prefix: string,
  visited: Set<object>,
  result: FlattenedObject
): void {
  if (visited.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key "${prefix.replace(/\.$/, "")}"`
    );
  }

  visited.add(obj);

  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      if (Object.keys(value).length === 0) {
        // Preserve empty objects as leaf values rather than silently dropping them
        result[fullKey] = value as LeafValue;
      } else {
        _flatten(value, fullKey, visited, result);
      }
    } else {
      result[fullKey] = value as LeafValue;
    }
  }

  // Remove after processing this path so diamond-shaped references (same object
  // reachable via two paths) don't trigger false-positive circular errors
  visited.delete(obj);
}

export default function flattenObject(
  obj: Record<string, unknown>
): FlattenedObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlattenedObject = {};
  _flatten(obj, "", new Set<object>(), result);
  return result;
}

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const mergeValues = (target: unknown, source: unknown): unknown => {
  if (isPlainObject(target) && isPlainObject(source)) {
    return deepMerge(target, source);
  }
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }
  return source;
};

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError("Both target and source must be plain objects");
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    result[key] = key in result
      ? mergeValues(result[key], source[key])
      : source[key];
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = Record<string, Primitive | unknown[]>;

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const path = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, path, result);
    } else {
      result[path] = value as Primitive | unknown[];
    }
  }

  return result;
}

