type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function range(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  return result;
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    const [from, to] =
      base === "*"
        ? [min, max]
        : base.includes("-")
          ? base.split("-").map((n) => clamp(parseInt(n, 10), min, max))
          : (() => { const v = clamp(parseInt(base, 10), min, max); return [v, max]; })();

    return range(from, to, step);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const [from, to] = parts.map((n) => clamp(parseInt(n, 10), min, max));
    if (from > to) {
      throw new RangeError(`Range start ${from} exceeds end ${to} in field "${field}"`);
    }
    return range(from, to);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  return [clamp(value, min, max)];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const values = new Set<number>(
    segments.flatMap((segment) => parseSegment(segment.trim(), field))
  );
  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const trimmed = expression.trim();
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  return Object.fromEntries(
    FIELD_ORDER.map((field, i) => [field, parseField(fields[i], field)])
  ) as CronExpression;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Readonly<Record<keyof CronFields, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: ReadonlyArray<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

function parseInteger(raw: string, context: string): number {
  const n = parseInt(raw, 10);
  if (isNaN(n) || raw.trim() === "" || String(n) !== raw.trim()) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} in "${context}" is outside the valid range [${min}, ${max}]`
    );
  }
}

function expandRange(start: number, end: number, step: number, expr: string): number[] {
  if (step <= 0) {
    throw new RangeError(`Step value must be >= 1 in "${expr}"`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in "${expr}"`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step expression: */n  or  start-end/n  or  start/n
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const rangeExpr = segment.slice(0, slashIdx);
    const stepStr   = segment.slice(slashIdx + 1);

    if (stepStr.includes("/")) {
      throw new Error(`Multiple slashes in segment "${segment}"`);
    }

    const step = parseInteger(stepStr, `step in "${segment}"`);
    if (step <= 0) {
      throw new RangeError(`Step must be >= 1 in "${segment}"`);
    }

    if (rangeExpr === "*") {
      return expandRange(min, max, step, segment);
    }

    if (rangeExpr.includes("-")) {
      const dashIdx  = rangeExpr.indexOf("-");
      const startVal = parseInteger(rangeExpr.slice(0, dashIdx), `range start in "${segment}"`);
      const endVal   = parseInteger(rangeExpr.slice(dashIdx + 1), `range end in "${segment}"`);
      assertInRange(startVal, min, max, segment);
      assertInRange(endVal,   min, max, segment);
      return expandRange(startVal, endVal, step, segment);
    }

    // start/n  → from start to max with step
    const startVal = parseInteger(rangeExpr, `start in "${segment}"`);
    assertInRange(startVal, min, max, segment);
    return expandRange(startVal, max, step, segment);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, segment);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIdx  = segment.indexOf("-");
    const startVal = parseInteger(segment.slice(0, dashIdx), `range start in "${segment}"`);
    const endVal   = parseInteger(segment.slice(dashIdx + 1), `range end in "${segment}"`);
    assertInRange(startVal, min, max, segment);
    assertInRange(endVal,   min, max, segment);
    return expandRange(startVal, endVal, 1, segment);
  }

  // Single value
  const value = parseInteger(segment, `"${segment}"`);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(expression: string, min: number, max: number): number[] {
  if (expression === "" || expression === undefined) {
    throw new Error("Empty cron field expression");
  }

  const parts = expression.split(",");

  if (parts.some((p) => p === "")) {
    throw new Error(`Trailing or consecutive commas in "${expression}"`);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
        `but received ${parts.length}: "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const range     = FIELD_RANGES[fieldName];
    try {
      result[fieldName] = parseField(parts[i], range.min, range.max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid ${fieldName} field "${parts[i]}": ${message}`);
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(val: unknown): val is PlainObject {
  if (val === null || typeof val !== "object") return false;
  const proto = Object.getPrototypeOf(val);
  return proto === Object.prototype || proto === null;
}

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function mergeInner(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  if (source === undefined) return target;

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    if (seen.has(source)) return seen.get(source);

    const result: PlainObject = Object.create(
      Object.getPrototypeOf(target) === null ? null : Object.prototype
    );
    seen.set(source, result);

    const keys = new Set([...Object.keys(target), ...Object.keys(source)]);

    for (const key of keys) {
      if (UNSAFE_KEYS.has(key)) continue;
      result[key] = mergeInner(target[key], source[key], seen);
    }

    return result;
  }

  return source;
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  const seen = new WeakMap<object, unknown>();
  return mergeInner(target, source, seen) as T & S;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : String(index);
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<CronField, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function rangeArray(start: number, end: number, step = 1): number[] {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step on wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step === 0) throw new RangeError(`Step value cannot be zero in "${segment}"`);
    return rangeArray(min, max, step);
  }

  // Range with optional step: n-m or n-m/s
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    const step  = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;
    assertInRange(start, min, max, segment);
    assertInRange(end,   min, max, segment);
    if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end} in "${segment}"`);
    if (step === 0)  throw new RangeError(`Step value cannot be zero in "${segment}"`);
    return rangeArray(start, end, step);
  }

  // Single numeric value
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    assertInRange(value, min, max, segment);
    return [value];
  }

  throw new SyntaxError(`Unrecognised cron segment: "${segment}"`);
}

function parseField(expression: string, config: FieldConfig): number[] {
  const parts = expression.split(",");
  if (parts.length === 0) throw new SyntaxError(`Empty field expression`);

  const values = parts.flatMap((part) => parseSegment(part.trim(), config));
  const unique = [...new Set(values)].sort((a, b) => a - b);
  return unique;
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], FIELD_CONFIGS[fieldName]);
  }

  return result;
}

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

function parseNonNegativeInt(raw: string, context: string): number {
  const s = raw.trim();
  if (!/^\d+$/.test(s)) {
    throw new Error(
      `Invalid value "${raw}" in ${context}: must be a non-negative integer`
    );
  }
  const n = parseInt(s, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Value "${raw}" in ${context} could not be parsed as an integer`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig, label: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} (${label}) is out of valid range [${config.min}–${config.max}] ` +
      `for field "${config.name}"`
    );
  }
}

function generateSequence(start: number, end: number, step: number): number[] {
  // Defensive: caller is responsible for ensuring start <= end and step > 0,
  // but guard anyway to avoid an infinite loop in the impossible case.
  if (step <= 0) throw new Error(`Internal error: step must be positive, got ${step}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parsePart(part: string, config: FieldConfig): number[] {
  const ctx = `field "${config.name}"`;
  const trimmed = part.trim();

  if (trimmed === "") {
    throw new Error(`Empty segment encountered in ${ctx}`);
  }

  // Handle step: "*/N", "V/N", or "V-W/N"
  if (trimmed.includes("/")) {
    const slashIdx = trimmed.lastIndexOf("/");
    const baseStr = trimmed.slice(0, slashIdx);
    const stepStr = trimmed.slice(slashIdx + 1);

    if (baseStr === "") {
      throw new Error(`Missing base before "/" in ${ctx}: "${trimmed}"`);
    }
    if (stepStr === "") {
      throw new Error(`Missing step after "/" in ${ctx}: "${trimmed}"`);
    }

    const step = parseNonNegativeInt(stepStr, ctx);
    if (step === 0) {
      throw new Error(`Step value of 0 is invalid in ${ctx}: "${trimmed}"`);
    }

    let start: number;
    let end: number;

    if (baseStr === "*") {
      start = config.min;
      end = config.max;
    } else if (baseStr.includes("-")) {
      const dashIdx = baseStr.indexOf("-");
      start = parseNonNegativeInt(baseStr.slice(0, dashIdx), ctx);
      end = parseNonNegativeInt(baseStr.slice(dashIdx + 1), ctx);
    } else {
      start = parseNonNegativeInt(baseStr, ctx);
      end = config.max;
    }

    assertInRange(start, config, "range start");
    assertInRange(end, config, "range end");
    if (start > end) {
      throw new Error(
        `Range start (${start}) must not exceed range end (${end}) in ${ctx}: "${trimmed}"`
      );
    }

    return generateSequence(start, end, step);
  }

  // Handle wildcard
  if (trimmed === "*") {
    return generateSequence(config.min, config.max, 1);
  }

  // Handle bare range: "V-W"
  if (trimmed.includes("-")) {
    const dashIdx = trimmed.indexOf("-");
    // Guard against a leading "-" being misinterpreted as negative numbers.
    if (dashIdx === 0) {
      throw new Error(`Negative numbers are not allowed in ${ctx}: "${trimmed}"`);
    }
    const start = parseNonNegativeInt(trimmed.slice(0, dashIdx), ctx);
    const end = parseNonNegativeInt(trimmed.slice(dashIdx + 1), ctx);

    assertInRange(start, config, "range start");
    assertInRange(end, config, "range end");
    if (start > end) {
      throw new Error(
        `Range start (${start}) must not exceed range end (${end}) in ${ctx}: "${trimmed}"`
      );
    }

    return generateSequence(start, end, 1);
  }

  // Handle single numeric value
  const value = parseNonNegativeInt(trimmed, ctx);
  assertInRange(value, config, "value");
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new Error(`Field "${config.name}" is empty`);
  }

  const segments = trimmed.split(",");
  const collected = new Set<number>();

  for (const segment of segments) {
    if (segment.trim() === "") {
      throw new Error(
        `Field "${config.name}" contains an empty segment (double comma or trailing comma): "${raw}"`
      );
    }
    for (const v of parsePart(segment, config)) {
      collected.add(v);
    }
  }

  if (collected.size === 0) {
    // Theoretically unreachable, but better than silently returning [].
    throw new Error(`Field "${config.name}" resolved to no valid values: "${raw}"`);
  }

  return Array.from(collected).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseNumber(token: string, field: CronField): number {
  const n = Number(token);
  if (!Number.isInteger(n) || token.trim() === "") {
    throw new SyntaxError(`Invalid numeric value "${token}" in field "${field}"`);
  }
  assertInRange(n, field);
  return n;
}

function expandRange(start: number, end: number, field: CronField): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${field}"`
    );
  }
  assertInRange(start, field);
  assertInRange(end, field);
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function expandStep(base: string, step: number, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (step <= 0) {
    throw new RangeError(`Step value must be positive in field "${field}"`);
  }

  let start: number;
  let end: number;

  if (base === "*") {
    start = min;
    end = max;
  } else if (base.includes("-")) {
    const [rawStart, rawEnd] = base.split("-");
    start = parseNumber(rawStart, field);
    end = parseNumber(rawEnd, field);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in field "${field}"`
      );
    }
  } else {
    start = parseNumber(base, field);
    end = max;
  }

  assertInRange(start, field);
  assertInRange(end, field);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  // Step expression: base/step  (e.g. "*/15", "0-30/5", "2/3")
  if (segment.includes("/")) {
    const slashIndex = segment.indexOf("/");
    const base = segment.slice(0, slashIndex);
    const stepStr = segment.slice(slashIndex + 1);
    const step = Number(stepStr);
    if (!Number.isInteger(step) || stepStr.trim() === "") {
      throw new SyntaxError(
        `Invalid step value "${stepStr}" in field "${field}"`
      );
    }
    return expandStep(base, step, field);
  }

  // Wildcard
  if (segment === "*") {
    const { min, max } = FIELD_RANGES[field];
    return expandRange(min, max, field);
  }

  // Range expression: start-end  (e.g. "1-5")
  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    const startStr = segment.slice(0, dashIndex);
    const endStr = segment.slice(dashIndex + 1);
    const start = parseNumber(startStr, field);
    const end = parseNumber(endStr, field);
    return expandRange(start, end, field);
  }

  // Plain number
  return [parseNumber(segment, field)];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty field "${field}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const v of parseSegment(trimmed, field)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length} in cron expression "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function deepMergeInto(
  target: PlainObject,
  source: PlainObject,
  seen: WeakMap<PlainObject, PlainObject>
): PlainObject {
  if (seen.has(source)) {
    return seen.get(source)!;
  }

  seen.set(source, target);

  for (const key of Object.keys(source)) {
    if (UNSAFE_KEYS.has(key)) continue;

    const sourceVal = source[key];
    const targetVal = target[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      target[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      target[key] = deepMergeInto({ ...targetVal }, sourceVal, seen);
    } else {
      target[key] = sourceVal;
    }
  }

  return target;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  return deepMergeInto({ ...target }, source, new WeakMap()) as T & S;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<FieldName, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function rangeArray(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function assertInRange(value: number, field: FieldName): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: "*"
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step on wildcard: "*/n"
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) throw new RangeError(`Step value must be >= 1, got ${step}`);
    const values: number[] = [];
    for (let v = min; v <= max; v += step) values.push(v);
    return values;
  }

  // Step on range: "a-b/n"
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const from = parseInt(stepRangeMatch[1], 10);
    const to   = parseInt(stepRangeMatch[2], 10);
    const step = parseInt(stepRangeMatch[3], 10);
    assertInRange(from, field);
    assertInRange(to, field);
    if (step < 1) throw new RangeError(`Step value must be >= 1, got ${step}`);
    const values: number[] = [];
    for (let v = from; v <= to; v += step) values.push(v);
    return values;
  }

  // Range: "a-b"
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const from = parseInt(rangeMatch[1], 10);
    const to   = parseInt(rangeMatch[2], 10);
    assertInRange(from, field);
    assertInRange(to, field);
    return rangeArray(from, to);
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    // Normalize Sunday: both 0 and 7 are valid in dayOfWeek, map 7 -> 0
    const normalized =
      field === "dayOfWeek" && value === 7 ? 0 : value;
    assertInRange(normalized, field);
    return [normalized];
  }

  throw new SyntaxError(`Unrecognised cron segment: "${segment}"`);
}

function parseField(expression: string, field: FieldName): number[] {
  const parts = expression.split(",");
  if (parts.length === 0) {
    throw new SyntaxError(`Empty field value for "${field}"`);
  }

  const collected = new Set<number>();
  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in list for field "${field}"`);
    }
    for (const value of parseSegment(trimmed, field)) {
      collected.add(value);
    }
  }

  return Array.from(collected).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  return {
    minute:     parseField(fields[0], "minute"),
    hour:       parseField(fields[1], "hour"),
    dayOfMonth: parseField(fields[2], "dayOfMonth"),
    month:      parseField(fields[3], "month"),
    dayOfWeek:  parseField(fields[4], "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (JSON.stringify(value) as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject>(target: T, source: Partial<T>): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key as keyof typeof source];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject | null | undefined,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      const nested = value as NestedObject;
      const nestedKeys = Object.keys(nested);
      if (nestedKeys.length === 0) {
        result[newKey] = {} as unknown as Primitive;
      } else {
        flattenObject(nested, newKey, result);
      }
    } else if (Array.isArray(value)) {
      flattenObject(
        value.reduce((acc, item, index) => ({ ...acc, [index]: item }), {} as NestedObject),
        newKey,
        result
      );
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

