type FlatValue = unknown;
type FlatResult = Record<string, FlatValue>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInternal(
  obj: Record<string, unknown>,
  prefix: string,
  seen: WeakSet<object>,
  result: FlatResult
): void {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at path: "${prefix || "<root>"}"`
    );
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty plain objects as leaf values rather than silently dropping them
    if (prefix !== "") {
      result[prefix] = obj;
    }
  } else {
    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

      const value = obj[key];
      const path = prefix === "" ? key : `${prefix}.${key}`;

      if (isPlainObject(value) && value !== null) {
        flattenInternal(
          value as Record<string, unknown>,
          path,
          seen,
          result
        );
      } else {
        result[path] = value;
      }
    }
  }

  // Delete after processing so shared (non-circular) references at sibling
  // paths don't incorrectly trigger the circular reference guard
  seen.delete(obj);
}

function flattenObject(obj: Record<string, unknown>): FlatResult {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlatResult = {};
  flattenInternal(obj, "", new WeakSet(), result);
  return result;
}

