type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

const isPlainObject = (value: unknown): value is NestedObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const flattenObject = (
  input: NestedObject,
  prefix = "",
  seen = new WeakSet<object>()
): FlatObject => {
  if (seen.has(input)) return {};
  seen.add(input);

  return Object.entries(input).reduce<FlatObject>((acc, [key, value]) => {
    const path = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const nested = flattenObject(value, path, seen);
      const hasChildren = Object.keys(nested).length > 0;
      return hasChildren
        ? { ...acc, ...nested }
        : { ...acc, [path]: {} };
    }

    return { ...acc, [path]: value as Primitive | unknown[] };
  }, {});
};

