export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldMeta {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_METADATA: readonly FieldMeta[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  6 },
] as const;

function assertStrictInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new TypeError(`Expected a non-negative integer, got "${raw}" (${context})`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new RangeError(`Integer overflow for "${raw}" (${context})`);
  }
  return n;
}

function assertInRange(value: number, meta: FieldMeta): void {
  if (value < meta.min || value > meta.max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${meta.min}–${meta.max}] for field "${meta.name}"`
    );
  }
}

function parsePart(part: string, meta: FieldMeta): number[] {
  if (part.length === 0) {
    throw new Error(`Empty token encountered in field "${meta.name}"`);
  }

  const slashIndex = part.indexOf("/");
  let base: string;
  let step: number;

  if (slashIndex !== -1) {
    base = part.slice(0, slashIndex);
    const stepRaw = part.slice(slashIndex + 1);
    if (stepRaw.length === 0) {
      throw new Error(`Missing step value after "/" in field "${meta.name}"`);
    }
    step = assertStrictInteger(stepRaw, `step in "${meta.name}"`);
    if (step < 1) {
      throw new RangeError(
        `Step must be ≥ 1, got ${step} in field "${meta.name}"`
      );
    }
  } else {
    base = part;
    step = 1;
  }

  let rangeMin: number;
  let rangeMax: number;

  if (base === "*") {
    rangeMin = meta.min;
    rangeMax = meta.max;
  } else {
    const dashIndex = base.indexOf("-");
    if (dashIndex !== -1) {
      const startRaw = base.slice(0, dashIndex);
      const endRaw   = base.slice(dashIndex + 1);
      if (startRaw.length === 0 || endRaw.length === 0) {
        throw new Error(`Malformed range "${base}" in field "${meta.name}"`);
      }
      rangeMin = assertStrictInteger(startRaw, `range start in "${meta.name}"`);
      rangeMax = assertStrictInteger(endRaw,   `range end in "${meta.name}"`);
      assertInRange(rangeMin, meta);
      assertInRange(rangeMax, meta);
      if (rangeMin > rangeMax) {
        throw new RangeError(
          `Range start ${rangeMin} exceeds end ${rangeMax} in field "${meta.name}"`
        );
      }
    } else {
      const value = assertStrictInteger(base, `value in "${meta.name}"`);
      assertInRange(value, meta);
      if (slashIndex === -1) {
        // Plain number, no step — return immediately; no loop needed.
        return [value];
      }
      // "N/S" — start at N, advance by S through to field max.
      rangeMin = value;
      rangeMax = meta.max;
    }
  }

  const result: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    result.push(v);
  }
  return result;
}

function parseField(expr: string, meta: FieldMeta): number[] {
  if (expr.length === 0) {
    throw new Error(`Empty expression for field "${meta.name}"`);
  }

  const parts = expr.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed.length === 0) {
      throw new Error(
        `Empty token in comma-separated list for field "${meta.name}"`
      );
    }
    for (const v of parsePart(trimmed, meta)) {
      seen.add(v);
    }
  }

  // Return a stable, ascending array — callers should not have to sort.
  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be empty or whitespace-only");
  }

  // Split on any run of whitespace so callers aren't punished for double-spaces.
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${fields.length} in "${trimmed}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields as [
    string, string, string, string, string
  ];

  return {
    minute:     parseField(minuteExpr, FIELD_METADATA[0]),
    hour:       parseField(hourExpr,   FIELD_METADATA[1]),
    dayOfMonth: parseField(domExpr,    FIELD_METADATA[2]),
    month:      parseField(monthExpr,  FIELD_METADATA[3]),
    dayOfWeek:  parseField(dowExpr,    FIELD_METADATA[4]),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flatten(
  obj: NestedObject | Array<unknown>,
  prefix: string,
  result: FlatObject
): void {
  const entries = Array.isArray(obj)
    ? obj.map((v, i) => [String(i), v] as const)
    : Object.entries(obj);

  for (const [key, value] of entries) {
    const dotKey = prefix ? `${prefix}.${key}` : key;

    if (value === null || value === undefined) {
      result[dotKey] = value as Primitive;
    } else if (Array.isArray(value)) {
      if (value.length === 0) {
        result[dotKey] = undefined;
      } else {
        flatten(value, dotKey, result);
      }
    } else if (typeof value === "object") {
      const nested = value as NestedObject;
      if (Object.keys(nested).length === 0) {
        result[dotKey] = undefined;
      } else {
        flatten(nested, dotKey, result);
      }
    } else {
      result[dotKey] = value as Primitive;
    }
  }
}

