type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: (keyof CronResult)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function rangeArray(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Invalid range: ${start}-${end} (start must be <= end)`);
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");

    if (stepPart === undefined || stepPart === "") {
      throw new SyntaxError(`Missing step value after "/" in field "${fieldName}"`);
    }

    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Step value must be a positive integer in field "${fieldName}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      rangeStart = parseInt(startStr, 10);
      rangeEnd = parseInt(endStr, 10);
      if (isNaN(rangeStart) || isNaN(rangeEnd)) {
        throw new SyntaxError(`Invalid range "${rangePart}" in field "${fieldName}"`);
      }
      assertInRange(rangeStart, min, max, fieldName);
      assertInRange(rangeEnd, min, max, fieldName);
    } else {
      rangeStart = parseInt(rangePart, 10);
      if (isNaN(rangeStart)) {
        throw new SyntaxError(`Invalid step expression "${segment}" in field "${fieldName}"`);
      }
      assertInRange(rangeStart, min, max, fieldName);
      rangeEnd = max;
    }

    const values: number[] = [];
    for (let v = rangeStart; v <= rangeEnd; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(field: string, config: FieldConfig, fieldName: string): number[] {
  const segments = field.split(",");

  if (segments.length === 0 || (segments.length === 1 && segments[0] === "")) {
    throw new SyntaxError(`Empty field "${fieldName}"`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${fieldName}"`);
    }
    const values = parseSegment(trimmed, config, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(fields[i], config, fieldName);
  }

  return result;
}

type FlatValue = string | number | boolean | null | undefined | symbol | bigint | unknown;

type FlattenedObject = Record<string, FlatValue>;

function isTraversable(value: unknown): value is Record<string | number, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  const isPlain = proto === Object.prototype || proto === null;
  const isArray = Array.isArray(value);
  if (!isPlain && !isArray) return false;
  // Treat empty objects/arrays as leaf values — flattening them would silently drop the key
  return Object.keys(value as object).length > 0;
}

function flatten(
  obj: Record<string | number, unknown>,
  prefix: string,
  result: FlattenedObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }
  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    // Keys containing dots are escaped to avoid ambiguous round-trip parsing
    const escapedKey = key.replace(/\./g, "\\.");
    const fullKey = prefix ? `${prefix}.${escapedKey}` : escapedKey;

    if (isTraversable(value)) {
      flatten(value as Record<string | number, unknown>, fullKey, result, ancestors);
    } else {
      result[fullKey] = value;
    }
  }

  // Remove after processing to allow the same object to appear at sibling paths (DAG),
  // while still catching true cycles on the active recursion stack
  ancestors.delete(obj);
}

export default function flattenObject(
  input: Record<string, unknown>
): FlattenedObject {
  if (input === null || typeof input !== "object" || Array.isArray(input)) {
    throw new TypeError("flattenObject expects a plain object as input");
  }

  const result: FlattenedObject = {};
  flatten(input as Record<string | number, unknown>, "", result, new WeakSet());
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: PlainObject, source: PlainObject): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return isPlainObject(source) ? { ...source } : (target ?? source);
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type FlatValue = Primitive | Date | RegExp | Function;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: FlatValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return true;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  result: FlatObject = {},
  seen = new WeakSet<object>()
): FlatObject {
  if (!isPlainObject(input)) {
    if (prefix !== "") {
      result[prefix] = input as FlatValue;
    }
    return result;
  }

  if (seen.has(input as object)) {
    if (prefix !== "") {
      result[prefix] = "[Circular]";
    }
    return result;
  }

  seen.add(input as object);

  const entries = Object.entries(input as NestedObject);

  if (entries.length === 0) {
    if (prefix !== "") {
      result[prefix] = Array.isArray(input) ? ([] as unknown as FlatValue) : ({} as unknown as FlatValue);
    }
    return result;
  }

  for (const [key, value] of entries) {
    if (key === "") continue;

    const newKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flattenObject(value, newKey, result, seen);
    } else {
      result[newKey] = value as FlatValue;
    }
  }

  seen.delete(input as object);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, flatKey, result);
    } else {
      result[flatKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in segment: "${segment}"`);
    }

    const start = base === "*" ? min : parseInt(base, 10);
    if (isNaN(start)) throw new SyntaxError(`Invalid base in step segment: "${segment}"`);
    clamp(start, min, max);

    return range(start, max).filter(v => (v - start) % step === 0);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range segment: "${segment}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in segment: "${segment}"`);
    }

    clamp(start, min, max);
    clamp(end,   min, max);

    return range(start, end);
  }

  // Literal: n
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron segment: "${segment}"`);

  return [clamp(value, min, max)];
};

const parseField = (expression: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  const values = expression
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), min, max));

  const unique = [...new Set(values)].sort((a, b) => a - b);
  return unique;
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
};

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
