}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(field: CronField, token: string, reason: string) {
    super(`Invalid cron expression for field "${field}" near "${token}": ${reason}`);
    this.name = "CronParseError";
  }
}

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) return NaN;
  return value;
};

const expandRange = (min: number, max: number): number[] =>
  Array.from({ length: max - min + 1 }, (_, i) => min + i);

const parseToken = (token: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  // Step: */n or a-b/n
  if (token.includes("/")) {
    const [rangepart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new CronParseError(field, token, "step must be a positive integer");
    }

    let base: number[];

    if (rangepart === "*") {
      base = expandRange(min, max);
    } else if (rangepart.includes("-")) {
      const [startStr, endStr] = rangepart.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end   = clamp(parseInt(endStr,   10), min, max);

      if (isNaN(start) || isNaN(end) || start > end) {
        throw new CronParseError(field, token, `range ${rangepart} is invalid`);
      }

      base = expandRange(start, end);
    } else {
      throw new CronParseError(field, token, "step expressions require '*' or 'a-b' as the base");
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Range: a-b
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);

    if (isNaN(start) || isNaN(end)) {
      throw new CronParseError(field, token, `range values must be within [${min}, ${max}]`);
    }

    if (start > end) {
      throw new CronParseError(field, token, "range start must not exceed range end");
    }

    return expandRange(start, end);
  }

  // Wildcard
  if (token === "*") {
    return expandRange(min, max);
  }

  // Literal number
  const value = parseInt(token, 10);

  if (isNaN(value)) {
    throw new CronParseError(field, token, "unrecognised token");
  }

  const clamped = clamp(value, min, max);

  if (isNaN(clamped)) {
    throw new CronParseError(field, token, `value ${value} is outside valid range [${min}, ${max}]`);
  }

  return [clamped];
};

const parseField = (expression: string, field: CronField): number[] => {
  const parts = expression.split(",");

  if (parts.length === 0) {
    throw new CronParseError(field, expression, "field must not be empty");
  }

  const values = parts.flatMap((part) => parseToken(part.trim(), field));

  // Deduplicate and sort ascending
  return [...new Set(values)].sort((a, b) => a - b);
};

const parseCron = (expression: string): ParsedCron => {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  return FIELD_ORDER.reduce<ParsedCron>((acc, field, index) => {
    acc[field] = parseField(fields[index], field);
    return acc;
  }, {} as ParsedCron);
};

export default parseCron;
export { CronParseError, type ParsedCron, type CronField };

type PlainObject = Record<string, unknown>;

const FORBIDDEN_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMergeInner(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, object>
): unknown {
  // Source is not an object or is null — source wins outright
  if (!isPlainObject(source) && !Array.isArray(source)) {
    return source;
  }

  // Guard against circular references in source
  if (seen.has(source as object)) {
    return seen.get(source as object);
  }

  // Both are arrays — concatenate
  if (Array.isArray(source)) {
    const targetArray = Array.isArray(target) ? target : [];
    const result = [...targetArray, ...source];
    seen.set(source, result);
    return result;
  }

  // Source is a plain object
  const targetObj: PlainObject = isPlainObject(target) ? { ...target } : {};
  seen.set(source as object, targetObj);

  for (const key of Object.keys(source)) {
    // Prototype pollution guard
    if (FORBIDDEN_KEYS.has(key)) continue;

    const sourceVal = (source as PlainObject)[key];
    const targetVal = targetObj[key];

    if (sourceVal === undefined) {
      // Explicit undefined in source — do not overwrite target
      continue;
    }

    targetObj[key] = deepMergeInner(targetVal, sourceVal, seen);
  }

  return targetObj;
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  const seen = new WeakMap<object, object>();
  return deepMergeInner(target, source, seen) as T & S;
}

type CronField = {
  min: number;
  max: number;
};

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELDS: [keyof CronResult, CronField][] = [
  ["minute",     { min: 0,  max: 59 }],
  ["hour",       { min: 0,  max: 23 }],
  ["dayOfMonth", { min: 1,  max: 31 }],
  ["month",      { min: 1,  max: 12 }],
  ["dayOfWeek",  { min: 0,  max: 6  }],
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, { min, max }: CronField, fieldName: string): number[] {
  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);

    if (!Number.isInteger(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(v => parseInt(v, 10));
        assertInRange(s, min, max, fieldName);
        assertInRange(e, min, max, fieldName);
        if (s > e) throw new RangeError(`Invalid range "${rangePart}" in field "${fieldName}"`);
        start = s;
        end = e;
      } else {
        const s = parseInt(rangePart, 10);
        assertInRange(s, min, max, fieldName);
        start = s;
      }
    }

    const result: number[] = [];
    for (let v = start; v <= end; v += step) {
      result.push(v);
    }
    return result;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    const [s, e] = parts.map(v => parseInt(v, 10));
    assertInRange(s, min, max, fieldName);
    assertInRange(e, min, max, fieldName);
    if (s > e) throw new RangeError(`Invalid range "${segment}" in field "${fieldName}"`);
    return Array.from({ length: e - s + 1 }, (_, i) => i + s);
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid token "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, field: CronField, fieldName: string): number[] {
  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty field "${fieldName}"`);
  }

  const values = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) throw new SyntaxError(`Empty segment in field "${fieldName}"`);
    for (const v of parseSegment(trimmed, field, fieldName)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}. Expression: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELDS.length; i++) {
    const [name, fieldDef] = FIELDS[i];
    result[name] = parseField(parts[i], fieldDef, name);
  }

  return result;
}

type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  seen: WeakSet<object> = new WeakSet()
): FlatObject {
  // Guard: treat non-objects passed directly as terminal values
  if (obj === null || typeof obj !== "object") {
    return prefix ? { [prefix]: obj } : {};
  }

  // Guard: circular reference — surface as a sentinel rather than infinite loop
  if (seen.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }
  seen.add(obj);

  const result: FlatObject = {};

  for (const key of Object.keys(obj)) {
    const value = (obj as Record<string, unknown>)[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    const isTraversable =
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&        // arrays are leaf values — don't explode them into "0", "1" keys
      Object.keys(value as object).length > 0; // empty objects are leaf values — preserve them

    if (isTraversable) {
      Object.assign(
        result,
        flattenObject(value as NestedObject, flatKey, seen)
      );
    } else {
      result[flatKey] = value;
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const full = range(min, max);

  // Wildcard
  if (segment === "*") return full;

  // Step with wildcard: */n
  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step: ${segment}`);
    return full.filter(v => (v - min) % step === 0);
  }

  // Range with optional step: a-b or a-b/n
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [rawFrom, rawTo] = rangePart.split("-").map(s => parseInt(s, 10));
    if (isNaN(rawFrom) || isNaN(rawTo)) throw new SyntaxError(`Invalid range: ${segment}`);
    const from = clamp(rawFrom, min, max);
    const to   = clamp(rawTo,   min, max);
    const values = range(from, to);
    if (stepPart !== undefined) {
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step: ${segment}`);
      return values.filter((_, i) => i % step === 0);
    }
    return values;
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const seen = new Set<number>();
    const result: number[] = [];
    for (const part of segment.split(",")) {
      for (const v of parseSegment(part.trim(), min, max)) {
        if (!seen.has(v)) { seen.add(v); result.push(v); }
      }
    }
    return result.sort((a, b) => a - b);
  }

  // Plain number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid cron token: ${segment}`);
  return [clamp(n, min, max)];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") throw new TypeError("Expression must be a string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${parts.length}`);
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, field, i) => {
    const { min, max } = FIELD_RANGES[field];
    acc[field] = parseSegment(parts[i], min, max);
    return acc;
  }, {} as CronFields);
}

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const mergeValues = (target: unknown, source: unknown): unknown => {
  if (isPlainObject(target) && isPlainObject(source)) {
    return deepMerge(target, source);
  }
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }
  return source;
};

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError("Both target and source must be plain objects");
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    result[key] = Object.prototype.hasOwnProperty.call(result, key)
      ? mergeValues(result[key], source[key])
      : source[key];
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function rangeArray(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(value: number, min: number, max: number, label: string): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${label}"`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number, label: string): number[] {
  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value "${stepPart}" in field "${label}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      start = clamp(s, min, max, label);
      end   = clamp(e, min, max, label);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max, label);
      end   = max;
    }

    if (start > end) throw new RangeError(`Invalid range in field "${label}"`);

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [rawStart, rawEnd] = segment.split("-");
    const start = clamp(parseInt(rawStart, 10), min, max, label);
    const end   = clamp(parseInt(rawEnd,   10), min, max, label);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${segment}" in field "${label}"`);
  return [clamp(value, min, max, label)];
}

function parseField(expression: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  // Comma-separated list — split and parse each segment, then deduplicate + sort
  const parts = expression.split(",");
  const collected = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new Error(`Empty segment in field "${fieldName}"`);
    for (const v of parseSegment(trimmed, min, max, fieldName)) {
      collected.add(v);
    }
  }

  return Array.from(collected).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(parts[i], fieldName);
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetValue = result[key];
    const sourceValue = source[key];

    if (Array.isArray(targetValue) && Array.isArray(sourceValue)) {
      result[key] = [...targetValue, ...sourceValue];
    } else if (isPlainObject(targetValue) && isPlainObject(sourceValue)) {
      result[key] = deepMerge(targetValue, sourceValue);
    } else {
      result[key] = sourceValue;
    }
  }

  return result as T & S;
}

export default deepMerge;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard: */n
  const stepWildcard = segment.match(/^\*\/(\d+)$/);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    if (step <= 0) throw new RangeError(`Step value must be positive, got ${step}`);
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  // Step with range: n-m/s
  const stepRange = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRange) {
    const start = clamp(parseInt(stepRange[1], 10), min, max);
    const end   = clamp(parseInt(stepRange[2], 10), min, max);
    const step  = parseInt(stepRange[3], 10);
    if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
    if (step <= 0)   throw new RangeError(`Step value must be positive, got ${step}`);
    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: n-m
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = clamp(parseInt(rangeMatch[1], 10), min, max);
    const end   = clamp(parseInt(rangeMatch[2], 10), min, max);
    if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
    return range(start, end);
  }

  // Single number
  if (/^\d+$/.test(segment)) {
    return [clamp(parseInt(segment, 10), min, max)];
  }

  throw new SyntaxError(`Unrecognized cron segment: "${segment}"`);
};

const parseField = (expression: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  const parts = expression.split(",");
  if (parts.length > 1) {
    const values = parts.flatMap((part) => parseSegment(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  return parseSegment(expression.trim(), min, max);
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute:     parseField(minuteExpr,     "minute"),
    hour:       parseField(hourExpr,       "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month:      parseField(monthExpr,      "month"),
    dayOfWeek:  parseField(dayOfWeekExpr,  "dayOfWeek"),
  };
};

export default parseCron;
export type { CronResult, CronField };

export type CronExpression = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_CONFIG = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  6 },
] as const;

type FieldConfig = (typeof FIELD_CONFIG)[number];

function parseIntStrict(s: string, context: string): number {
  if (!/^\d+$/.test(s)) {
    throw new Error(`Invalid integer "${s}" in ${context}`);
  }
  const n = Number(s);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Value "${s}" exceeds safe integer bounds in ${context}`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of valid range [${min}, ${max}] in ${context}`);
  }
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string,
): number[] {
  const ctx = `field "${fieldName}"`;
  const values: number[] = [];

  // ── Step: */n  |  a/n  |  a-b/n ────────────────────────────────────────────
  const slashIdx = segment.indexOf("/");
  if (slashIdx !== -1) {
    if (slashIdx === 0) {
      throw new Error(`Missing base before "/" in ${ctx}`);
    }
    if (slashIdx === segment.length - 1) {
      throw new Error(`Missing step value after "/" in ${ctx}`);
    }

    const stepStr = segment.slice(slashIdx + 1);
    const step    = parseIntStrict(stepStr, ctx);
    if (step <= 0) {
      throw new Error(`Step must be a positive integer in ${ctx}`);
    }

    const baseStr = segment.slice(0, slashIdx);
    let rangeMin: number;
    let rangeMax: number;

    if (baseStr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (baseStr.includes("-")) {
      const parts = baseStr.split("-");
      if (parts.length !== 2 || parts[0] === "" || parts[1] === "") {
        throw new Error(`Invalid range "${baseStr}" in ${ctx}`);
      }
      rangeMin = parseIntStrict(parts[0], ctx);
      rangeMax = parseIntStrict(parts[1], ctx);
      assertInRange(rangeMin, min, max, ctx);
      assertInRange(rangeMax, min, max, ctx);
      if (rangeMin > rangeMax) {
        throw new Error(`Range start ${rangeMin} exceeds end ${rangeMax} in ${ctx}`);
      }
    } else {
      rangeMin = parseIntStrict(baseStr, ctx);
      assertInRange(rangeMin, min, max, ctx);
      rangeMax = max;
    }

    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    return values;
  }

  // ── Wildcard ─────────────────────────────────────────────────────────────────
  if (segment === "*") {
    for (let v = min; v <= max; v++) {
      values.push(v);
    }
    return values;
  }

  // ── Range: a-b ───────────────────────────────────────────────────────────────
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2 || parts[0] === "" || parts[1] === "") {
      throw new Error(`Invalid range "${segment}" in ${ctx}`);
    }
    const start = parseIntStrict(parts[0], ctx);
    const end   = parseIntStrict(parts[1], ctx);
    assertInRange(start, min, max, ctx);
    assertInRange(end,   min, max, ctx);
    if (start > end) {
      throw new Error(`Range start ${start} exceeds end ${end} in ${ctx}`);
    }
    for (let v = start; v <= end; v++) {
      values.push(v);
    }
    return values;
  }

  // ── Single value ─────────────────────────────────────────────────────────────
  const num = parseIntStrict(segment, ctx);
  assertInRange(num, min, max, ctx);
  values.push(num);
  return values;
}

function parseField(
  field: string,
  { name, min, max }: FieldConfig,
): number[] {
  if (!field || field.trim() === "") {
    throw new Error(`Empty value for field "${name}"`);
  }

  const segments = field.split(",");
  const seen     = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(
        `Empty segment in comma-separated list for field "${name}" — trailing/double commas are not allowed`,
      );
    }
    for (const v of parseSegment(trimmed, min, max, name)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new Error(`Field "${name}" resolved to an empty value set`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`,
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `but got ${fields.length} field(s): "${expression}"`,
    );
  }

  return {
    minute:     parseField(fields[0], FIELD_CONFIG[0]),
    hour:       parseField(fields[1], FIELD_CONFIG[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIG[2]),
    month:      parseField(fields[3], FIELD_CONFIG[3]),
    dayOfWeek:  parseField(fields[4], FIELD_CONFIG[4]),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => i + start);

const parseSegment = (segment: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangeOrStar, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value in "${segment}"`);
    }

    const [start, end] =
      rangeOrStar === "*"
        ? [min, max]
        : rangeOrStar.split("-").map(Number);

    if (isNaN(start) || isNaN(end) || start > end) {
      throw new SyntaxError(`Invalid range in step expression "${segment}"`);
    }

    clamp(start, min, max);
    clamp(end, min, max);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${segment}"`);
    }

    clamp(start, min, max);
    clamp(end,   min, max);

    return range(start, end);
  }

  // List: a,b,c — recurse on each element
  if (segment.includes(",")) {
    const values = segment
      .split(",")
      .flatMap(part => parseSegment(part.trim(), field));

    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Unrecognised cron token "${segment}"`);
  }

  return [clamp(value, min, max)];
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldNames: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteStr, hourStr, domStr, monthStr, dowStr,
  ].map((segment, i) => parseSegment(segment, fieldNames[i]));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
};

export default parseCron;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function isSafeKey(key: string): boolean {
  return key !== "__proto__" && key !== "constructor" && key !== "prototype";
}

function deepMergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, object>
): unknown {
  // Source wins for all non-mergeable combinations
  if (source === undefined) return target;
  if (source === null || target === null) return source;

  // Both arrays → concatenate (deep clone source items to avoid shared references)
  if (Array.isArray(target) && Array.isArray(source)) {
    const merged = [...target] as unknown[];
    for (const item of source) {
      merged.push(isPlainObject(item) ? deepMergeInternal({}, item, seen) : item);
    }
    return merged;
  }

  // Both plain objects → recursive merge
  if (isPlainObject(target) && isPlainObject(source)) {
    // Guard against circular references
    if (seen.has(source as object)) {
      return seen.get(source as object);
    }

    const result: PlainObject = Object.assign(Object.create(null), target);
    seen.set(source as object, result);

    for (const key of Object.keys(source)) {
      if (!isSafeKey(key)) continue;

      const sourceVal = source[key];
      const targetVal = Object.prototype.hasOwnProperty.call(result, key)
        ? result[key]
        : undefined;

      result[key] = deepMergeInternal(targetVal, sourceVal, seen);
    }

    return result;
  }

  // Type mismatch (e.g. object vs array, primitive vs object) → source wins
  // Also handles all primitive cases
  if (isPlainObject(source)) {
    // Clone to prevent external mutation of the returned object
    return deepMergeInternal({}, source, seen);
  }
  if (Array.isArray(source)) {
    return deepMergeInternal([], source, seen);
  }

  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${JSON.stringify(target)}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${JSON.stringify(source)}`);
  }

  return deepMergeInternal(target, source, new WeakMap()) as T & S;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const mergeValues = (target: unknown, source: unknown): unknown => {
  if (isPlainObject(target) && isPlainObject(source)) {
    return deepMerge(target, source);
  }
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }
  return source;
};

function deepMerge(target: PlainObject, source: PlainObject): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError("Both target and source must be plain objects");
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    result[key] = Object.prototype.hasOwnProperty.call(target, key)
      ? mergeValues(target[key], source[key])
      : source[key];
  }

  return result;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (JSON.stringify(value) as unknown as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: PlainObject, source: PlainObject): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return isPlainObject(source) ? { ...source } : isPlainObject(target) ? { ...target } : {};
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

export default deepMerge;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<CronField, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function parsePositiveInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected a non-negative integer but got "${trimmed}" in ${context}`);
  }
  const n = parseInt(trimmed, 10);
  if (isNaN(n)) {
    throw new Error(`Failed to parse integer "${trimmed}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of the valid range [${min}, ${max}] in ${context}`
    );
  }
}

function expandValues(
  start: number,
  end: number,
  step: number,
  fieldMin: number,
  fieldMax: number,
  context: string
): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) exceeds range end (${end}) in ${context}`
    );
  }
  if (step <= 0) {
    throw new RangeError(
      `Step value must be a positive integer but got ${step} in ${context}`
    );
  }
  assertInRange(start, fieldMin, fieldMax, context);
  assertInRange(end,   fieldMin, fieldMax, context);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  fieldMin: number,
  fieldMax: number,
  fieldName: string
): number[] {
  const ctx = `field "${fieldName}", segment "${segment}"`;

  // Step expressions: "*/n", "a-b/n", "a/n"
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const rangePart = segment.slice(0, slashIdx);
    const stepPart  = segment.slice(slashIdx + 1);

    if (!rangePart || !stepPart) {
      throw new Error(`Malformed step expression "${segment}" in ${ctx}`);
    }

    const step = parsePositiveInteger(stepPart, ctx);
    if (step === 0) {
      throw new RangeError(`Step value must not be zero in ${ctx}`);
    }

    if (rangePart === "*") {
      return expandValues(fieldMin, fieldMax, step, fieldMin, fieldMax, ctx);
    }

    if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Malformed range "${rangePart}" in ${ctx}`);
      }
      const start = parsePositiveInteger(dashParts[0], ctx);
      const end   = parsePositiveInteger(dashParts[1], ctx);
      return expandValues(start, end, step, fieldMin, fieldMax, ctx);
    }

    // "n/step" — start at n, step through to fieldMax
    const start = parsePositiveInteger(rangePart, ctx);
    assertInRange(start, fieldMin, fieldMax, ctx);
    return expandValues(start, fieldMax, step, fieldMin, fieldMax, ctx);
  }

  // Bare wildcard
  if (segment === "*") {
    return expandValues(fieldMin, fieldMax, 1, fieldMin, fieldMax, ctx);
  }

  // Range: "a-b"
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Malformed range "${segment}" in ${ctx}`);
    }
    const start = parsePositiveInteger(dashParts[0], ctx);
    const end   = parsePositiveInteger(dashParts[1], ctx);
    return expandValues(start, end, 1, fieldMin, fieldMax, ctx);
  }

  // Single number
  const value = parsePositiveInteger(segment, ctx);
  assertInRange(value, fieldMin, fieldMax, ctx);
  return [value];
}

function parseField(
  expression: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  if (!expression || expression.trim() === "") {
    throw new Error(`Empty expression for field "${fieldName}"`);
  }

  const { min, max } = config;
  const segments = expression.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(
        `Empty segment in comma-separated list for field "${fieldName}"`
      );
    }
    for (const v of parseSegment(trimmed, min, max, fieldName)) {
      valueSet.add(v);
    }
  }

  if (valueSet.size === 0) {
    throw new Error(`No valid values resolved for field "${fieldName}"`);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must be a non-null string");
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty or whitespace-only");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, ` +
      `got ${fields.length} in "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], FIELD_CONFIGS[fieldName], fieldName);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, field: CronField): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step on wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) {
      throw new RangeError(`Step value must be >= 1 for field "${field}"`);
    }
    const values: number[] = [];
    for (let v = min; v <= max; v += step) {
      values.push(v);
    }
    return values;
  }

  // Step on range: n-m/s
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const start = parseInt(stepRangeMatch[1], 10);
    const end   = parseInt(stepRangeMatch[2], 10);
    const step  = parseInt(stepRangeMatch[3], 10);
    assertInRange(start, min, max, field);
    assertInRange(end,   min, max, field);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} for field "${field}"`);
    }
    if (step < 1) {
      throw new RangeError(`Step value must be >= 1 for field "${field}"`);
    }
    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: n-m
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    assertInRange(start, min, max, field);
    assertInRange(end,   min, max, field);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} for field "${field}"`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    // Normalize dayOfWeek: 7 is treated as Sunday (0)
    const normalized = field === "dayOfWeek" && value === 7 ? 0 : value;
    assertInRange(normalized, min, max, field);
    return [normalized];
  }

  throw new SyntaxError(`Unrecognized segment "${segment}" in field "${field}"`);
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const seen = new Set<number>();
  const values: number[] = [];

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const v of parseSegment(trimmed, field)) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length} in cron expression "${expression}"`
    );
  }

  return {
    minute:     parseField(fields[0], "minute"),
    hour:       parseField(fields[1], "hour"),
    dayOfMonth: parseField(fields[2], "dayOfMonth"),
    month:      parseField(fields[3], "month"),
    dayOfWeek:  parseField(fields[4], "dayOfWeek"),
  };
}

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const mergeValues = (target: unknown, source: unknown): unknown => {
  if (isPlainObject(target) && isPlainObject(source)) {
    return deepMerge(target, source);
  }
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }
  return source;
};

const deepMerge = (target: PlainObject, source: PlainObject): PlainObject => {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    throw new TypeError("Both target and source must be plain objects");
  }

  const allKeys = new Set([...Object.keys(target), ...Object.keys(source)]);

  return Array.from(allKeys).reduce<PlainObject>((merged, key) => {
    const hasTarget = Object.prototype.hasOwnProperty.call(target, key);
    const hasSource = Object.prototype.hasOwnProperty.call(source, key);

    merged[key] =
      hasTarget && hasSource
        ? mergeValues(target[key], source[key])
        : hasSource
          ? source[key]
          : target[key];

    return merged;
  }, {});
};

export default deepMerge;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, field: CronField): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseInteger(raw: string, field: CronField): number {
  const n = parseInt(raw, 10);
  if (isNaN(n) || raw.trim() !== String(n)) {
    throw new SyntaxError(`Invalid integer "${raw}" in field "${field}"`);
  }
  return n;
}

function expandWildcard(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step: */N or R-R/N
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    if (!stepPart || stepPart.includes("/")) {
      throw new SyntaxError(`Invalid step expression "${segment}" in field "${field}"`);
    }

    const step = parseInteger(stepPart, field);
    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer in field "${field}", got ${step}`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-");
      rangeMin = parseInteger(lo, field);
      rangeMax = parseInteger(hi, field);
      assertInRange(rangeMin, min, max, field);
      assertInRange(rangeMax, min, max, field);
      if (rangeMin > rangeMax) {
        throw new RangeError(`Range start ${rangeMin} exceeds end ${rangeMax} in field "${field}"`);
      }
    } else {
      rangeMin = parseInteger(rangePart, field);
      assertInRange(rangeMin, min, max, field);
      rangeMax = max;
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    return values;
  }

  // Wildcard: *
  if (segment === "*") {
    return expandWildcard(min, max);
  }

  // Range: N-N
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const lo = parseInteger(parts[0], field);
    const hi = parseInteger(parts[1], field);
    assertInRange(lo, min, max, field);
    assertInRange(hi, min, max, field);
    if (lo > hi) {
      throw new RangeError(`Range start ${lo} exceeds end ${hi} in field "${field}"`);
    }
    return Array.from({ length: hi - lo + 1 }, (_, i) => lo + i);
  }

  // Single value
  const value = parseInteger(segment, field);
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  if (segments.length === 0 || segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(`Empty segment in field "${field}": "${expression}"`);
  }

  const collected = new Set<number>();
  for (const segment of segments) {
    const values = parseSegment(segment.trim(), field);
    for (const v of values) {
      // Normalize Sunday: both 0 and 7 are valid aliases; store as 0
      if (field === "dayOfWeek" && v === 7) {
        collected.add(0);
      } else {
        collected.add(v);
      }
    }
  }

  return Array.from(collected).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function deepMergeInto(
  target: PlainObject,
  source: PlainObject,
  seen: WeakMap<PlainObject, PlainObject>
): PlainObject {
  if (seen.has(source)) {
    return seen.get(source)!;
  }

  seen.set(source, target);

  for (const key of Object.keys(source)) {
    if (UNSAFE_KEYS.has(key)) continue;

    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

    const sourceVal = source[key];
    const targetVal = Object.prototype.hasOwnProperty.call(target, key)
      ? target[key]
      : undefined;

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      target[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      target[key] = deepMergeInto({ ...targetVal }, sourceVal, seen);
    } else if (isPlainObject(sourceVal)) {
      target[key] = deepMergeInto({}, sourceVal, seen);
    } else if (Array.isArray(sourceVal)) {
      target[key] = [...sourceVal];
    } else {
      target[key] = sourceVal;
    }
  }

  return target;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`);
  }

  return deepMergeInto({ ...target }, source, new WeakMap()) as T & S;
}

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const deepMerge = <T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S => {
  const result = { ...target } as PlainObject;

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
};

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  return source !== undefined ? source : target;
}

export default deepMerge;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_CONFIG = [
  { name: "minute" as const, min: 0, max: 59 },
  { name: "hour" as const, min: 0, max: 23 },
  { name: "dayOfMonth" as const, min: 1, max: 31 },
  { name: "month" as const, min: 1, max: 12 },
  { name: "dayOfWeek" as const, min: 0, max: 6 },
] as const;

function parseStrictInt(s: string, context: string): number {
  if (!/^\d+$/.test(s)) {
    throw new Error(`Expected a non-negative integer but got "${s}" in ${context}`);
  }
  const n = parseInt(s, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow for value "${s}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of allowed range [${min}, ${max}] in ${context}`
    );
  }
}

function generateRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function parseToken(
  raw: string,
  fieldName: string,
  min: number,
  max: number
): number[] {
  const token = raw.trim();
  if (token === "") {
    throw new Error(`Empty token encountered in field "${fieldName}"`);
  }

  const slashIndex = token.indexOf("/");
  let base: string;
  let step: number | null = null;

  if (slashIndex !== -1) {
    base = token.substring(0, slashIndex);
    const stepStr = token.substring(slashIndex + 1);
    if (stepStr === "") {
      throw new Error(`Missing step value after "/" in "${token}" (field "${fieldName}")`);
    }
    step = parseStrictInt(stepStr, `step of field "${fieldName}"`);
    if (step === 0) {
      throw new Error(`Step value must be >= 1, got 0 in field "${fieldName}"`);
    }
  } else {
    base = token;
  }

  let rangeStart: number;
  let rangeEnd: number;

  if (base === "*") {
    rangeStart = min;
    rangeEnd = max;
  } else if (base.includes("-")) {
    // Guard against leading/trailing hyphens (e.g., "-5" or "5-")
    const dashIndex = base.indexOf("-");
    const startStr = base.substring(0, dashIndex);
    const endStr = base.substring(dashIndex + 1);

    if (startStr === "" || endStr === "") {
      throw new Error(
        `Malformed range "${base}" in field "${fieldName}": missing start or end`
      );
    }
    // endStr must not contain another hyphen (e.g., "1-5-3" is invalid)
    if (endStr.includes("-")) {
      throw new Error(
        `Malformed range "${base}" in field "${fieldName}": too many hyphens`
      );
    }

    rangeStart = parseStrictInt(startStr, `range start of field "${fieldName}"`);
    rangeEnd = parseStrictInt(endStr, `range end of field "${fieldName}"`);

    assertInRange(rangeStart, min, max, `range start of field "${fieldName}"`);
    assertInRange(rangeEnd, min, max, `range end of field "${fieldName}"`);

    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start (${rangeStart}) must not exceed range end (${rangeEnd}) in field "${fieldName}"`
      );
    }
  } else {
    const num = parseStrictInt(base, `value of field "${fieldName}"`);
    assertInRange(num, min, max, `field "${fieldName}"`);
    rangeStart = num;
    // A bare number with a step extends to max (e.g., "5/15" in minutes → 5,20,35,50)
    rangeEnd = step !== null ? max : num;
  }

  if (step !== null) {
    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      result.push(i);
    }
    if (result.length === 0) {
      throw new Error(
        `Step expression produced no values in field "${fieldName}" (start=${rangeStart}, end=${rangeEnd}, step=${step})`
      );
    }
    return result;
  }

  return generateRange(rangeStart, rangeEnd);
}

function parseField(
  raw: string,
  fieldName: string,
  min: number,
  max: number
): number[] {
  const field = raw.trim();
  if (field === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const parts = field.split(",");
  if (parts.some((p) => p.trim() === "")) {
    throw new Error(
      `Field "${fieldName}" contains an empty segment (check for trailing/leading commas)`
    );
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (const v of parseToken(part, fieldName, min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${fields.length}`
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_CONFIG.length; i++) {
    const { name, min, max } = FIELD_CONFIG[i];
    result[name] = parseField(fields[i], name, min, max);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: PlainObject, source: PlainObject): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return isPlainObject(source) ? { ...source } : (target ?? source) as PlainObject;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, unknown>
): unknown {
  // Primitives and null from source overwrite unconditionally
  if (source === null || typeof source !== "object") {
    return source;
  }

  // Guard against circular references in source
  if (seen.has(source as object)) {
    return seen.get(source as object);
  }

  // Arrays: concatenate (never element-wise merge)
  if (Array.isArray(source)) {
    const merged = Array.isArray(target)
      ? [...target, ...source]
      : [...source];
    seen.set(source, merged);
    return merged;
  }

  // Plain objects: recurse
  if (isPlainObject(source)) {
    // If target is not a plain object, start with an empty base
    const base: PlainObject = isPlainObject(target) ? { ...target } : {};
    // Register early so circular back-references resolve correctly
    seen.set(source, base);

    for (const key of Object.keys(source)) {
      // Prototype pollution guard
      if (UNSAFE_KEYS.has(key)) continue;
      base[key] = mergeInternal(base[key], source[key], seen);
    }

    return base;
  }

  // Non-plain objects (Date, RegExp, Map, Set, …): overwrite, never clone
  return source;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: 'target' must be a plain object, got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: 'source' must be a plain object, got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInternal(target, source, new WeakMap()) as T & S;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step value: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      const [startStr, endStr] = rangePart.split("-");
      rangeMin = parseInt(startStr, 10);
      rangeMax = endStr !== undefined ? parseInt(endStr, 10) : rangeMin;

      if (isNaN(rangeMin) || isNaN(rangeMax)) {
        throw new Error(`Invalid range in step expression: "${rangePart}"`);
      }

      if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
        throw new Error(
          `Range "${rangePart}" out of bounds [${min}, ${max}]`
        );
      }
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard: *
  if (segment === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${segment}"`);
    }

    if (start < min || end > max || start > end) {
      throw new Error(
        `Range "${segment}" out of bounds [${min}, ${max}]`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value: "${segment}"`);
  }

  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
  }

  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const parts = expression.split(",");
  const seen  = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in field "${field}": "${expression}"`);
    }

    const values = parseSegment(trimmed, min, max);
    for (const v of values) {
      seen.add(v);
    }
  }

  // Normalise dayOfWeek: 7 is an alias for 0 (Sunday)
  if (field === "dayOfWeek" && seen.has(7)) {
    seen.delete(7);
    seen.add(0);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function range(from: number, to: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function clamp(value: number, min: number, max: number, context: string): number {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] in field "${context}"`
    );
  }
  return value;
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step "${stepPart}" in field "${field}"`);
    }

    if (rangePart === "*") {
      return range(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      return range(
        clamp(lo, min, max, field),
        clamp(hi, min, max, field),
        step
      );
    }

    const base = parseInt(rangePart, 10);
    return range(clamp(base, min, max, field), max, step);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi)) {
      throw new Error(`Invalid range "${segment}" in field "${field}"`);
    }
    return range(
      clamp(lo, min, max, field),
      clamp(hi, min, max, field)
    );
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${segment}" in field "${field}"`);
  }
  return [clamp(value, min, max, field)];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), field)) {
      values.add(v);
    }
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const trimmed = expression.trim().replace(/\s+/g, " ");
  const parts = trimmed.split(" ");

  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length}. Expression: "${expression}"`
    );
  }

  const [minute, hour, dayOfMonth, month, dayOfWeek] = FIELD_ORDER.map(
    (field, i) => parseField(parts[i], field)
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const range = (from: number, to: number, step = 1): number[] => {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
};

const dedupe = (values: number[]): number[] =>
  [...new Set(values)].sort((a, b) => a - b);

const clamp = (value: number, min: number, max: number, field: CronField): number => {
  if (value < min || value > max)
    throw new Error(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  return value;
};

const parseSegment = (segment: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step)) throw new Error(`Invalid step "${stepStr}" in field "${field}"`);

    if (rangePart === "*") {
      return range(min, max, step);
    } else if (rangePart.includes("-")) {
      const [fromStr, toStr] = rangePart.split("-");
      const from = clamp(parseInt(fromStr, 10), min, max, field);
      const to   = clamp(parseInt(toStr,   10), min, max, field);
      if (from > to) throw new Error(`Invalid range ${from}-${to} in field "${field}"`);
      return range(from, to, step);
    }
    throw new Error(`Invalid step expression "${segment}" in field "${field}"`);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = clamp(parseInt(fromStr, 10), min, max, field);
    const to   = clamp(parseInt(toStr,   10), min, max, field);
    if (from > to) throw new Error(`Invalid range ${from}-${to} in field "${field}"`);
    return range(from, to);
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid token "${segment}" in field "${field}"`);
  return [clamp(value, min, max, field)];
};

const parseField = (expression: string, field: CronField): number[] =>
  dedupe(expression.split(",").flatMap(segment => parseSegment(segment.trim(), field)));

const parseCron = (expression: string): ParsedCron => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
};

export default parseCron;
export type { ParsedCron, CronField };

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof ParsedCron;

interface FieldConfig {
  name: FieldName;
  min: number;
  max: number;
  /** Some fields accept an extended max during parsing (e.g. dayOfWeek accepts 7 as alias for 0) */
  acceptedMax: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59, acceptedMax: 59 },
  { name: "hour",       min: 0,  max: 23, acceptedMax: 23 },
  { name: "dayOfMonth", min: 1,  max: 31, acceptedMax: 31 },
  { name: "month",      min: 1,  max: 12, acceptedMax: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6,  acceptedMax: 7  }, // 7 is a Sunday alias
];

function buildRange(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Range start ${from} exceeds end ${to}`);
  const out: number[] = [];
  for (let i = from; i <= to; i++) out.push(i);
  return out;
}

function parseInteger(raw: string, fieldName: FieldName): number {
  if (!/^\d+$/.test(raw)) {
    throw new TypeError(`Non-numeric token "${raw}" in field "${fieldName}"`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isFinite(n)) throw new TypeError(`Could not parse "${raw}" as integer`);
  return n;
}

function assertInBounds(n: number, min: number, acceptedMax: number, fieldName: FieldName): void {
  if (n < min || n > acceptedMax) {
    throw new RangeError(
      `Value ${n} is out of bounds [${min}–${acceptedMax}] for field "${fieldName}"`
    );
  }
}

/** Parse a single atom: a number, a range (M-N), or a step (expr/S). No commas here. */
function parseAtom(token: string, config: FieldConfig): number[] {
  const { name, min, acceptedMax } = config;

  // ── Step: expr/S ──────────────────────────────────────────────
  if (token.includes("/")) {
    const slashCount = (token.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(`Unexpected multiple "/" in token "${token}" for field "${name}"`);
    }
    const slashIdx = token.indexOf("/");
    const lhs = token.slice(0, slashIdx);
    const rhs = token.slice(slashIdx + 1);

    if (!rhs || !/^\d+$/.test(rhs)) {
      throw new SyntaxError(`Invalid step value "${rhs}" in "${token}" for field "${name}"`);
    }
    const step = parseInt(rhs, 10);
    if (step <= 0) {
      throw new RangeError(`Step must be ≥ 1, got ${step} in "${token}" for field "${name}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (lhs === "*") {
      rangeMin = min;
      rangeMax = acceptedMax;
    } else if (lhs.includes("-")) {
      [rangeMin, rangeMax] = parseRangePair(lhs, config);
    } else {
      rangeMin = parseInteger(lhs, name);
      assertInBounds(rangeMin, min, acceptedMax, name);
      rangeMax = acceptedMax;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) values.push(i);
    return values;
  }

  // ── Wildcard ──────────────────────────────────────────────────
  if (token === "*") {
    return buildRange(min, acceptedMax);
  }

  // ── Range: M-N ───────────────────────────────────────────────
  if (token.includes("-")) {
    const [lo, hi] = parseRangePair(token, config);
    return buildRange(lo, hi);
  }

  // ── Single integer ────────────────────────────────────────────
  const n = parseInteger(token, name);
  assertInBounds(n, min, acceptedMax, name);
  return [n];
}

function parseRangePair(token: string, config: FieldConfig): [number, number] {
  const { name, min, acceptedMax } = config;
  const parts = token.split("-");
  if (parts.length !== 2 || parts[0] === "" || parts[1] === "") {
    throw new SyntaxError(`Malformed range "${token}" in field "${name}"`);
  }
  const lo = parseInteger(parts[0], name);
  const hi = parseInteger(parts[1], name);
  assertInBounds(lo, min, acceptedMax, name);
  assertInBounds(hi, min, acceptedMax, name);
  if (lo > hi) {
    throw new RangeError(`Range start ${lo} exceeds end ${hi} in field "${name}"`);
  }
  return [lo, hi];
}

function parseFieldExpr(expr: string, config: FieldConfig): number[] {
  if (!expr || expr.trim() === "") {
    throw new SyntaxError(`Empty token for field "${config.name}"`);
  }

  const raw = expr.trim();

  // ── Comma list: split and recurse, then union ─────────────────
  if (raw.includes(",")) {
    const seen = new Set<number>();
    for (const part of raw.split(",")) {
      const trimmed = part.trim();
      if (!trimmed) {
        throw new SyntaxError(`Empty segment in comma list "${raw}" for field "${config.name}"`);
      }
      for (const v of parseAtom(trimmed, config)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseAtom(raw, config);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // 7 is a widely-accepted alias for 0 (Sunday); normalise and deduplicate.
  const normalized = new Set(values.map((v) => (v === 7 ? 0 : v)));
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    let values = parseFieldExpr(fields[i], config);

    if (config.name === "dayOfWeek") {
      values = normalizeDayOfWeek(values);
    }

    result[config.name] = values;
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: PlainObject, source: PlainObject): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return isPlainObject(source) ? structuredClone(source) : isPlainObject(target) ? structuredClone(target) : ({} as PlainObject);
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (JSON.stringify(value) as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => i + start);

const clamp = (values: number[], min: number, max: number): number[] =>
  values.filter(v => v >= min && v <= max);

const assertInRange = (value: number, min: number, max: number, context: string): void => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
};

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  if (segment === "*") {
    return range(min, max);
  }

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${segment}"`);
    }
    return range(min, max).filter(v => (v - min) % step === 0);
  }

  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step in "${segment}"`);
    }
    if (rangePart === "*") {
      return range(min, max).filter(v => (v - min) % step === 0);
    }
    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range in "${segment}"`);
      assertInRange(start, min, max, segment);
      assertInRange(end, min, max, segment);
      if (start > end) throw new RangeError(`Range start > end in "${segment}"`);
      return range(start, end).filter(v => (v - start) % step === 0);
    }
    const base = parseInt(rangePart, 10);
    if (isNaN(base)) throw new SyntaxError(`Invalid base in "${segment}"`);
    assertInRange(base, min, max, segment);
    return clamp(range(base, max).filter(v => (v - base) % step === 0), min, max);
  }

  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range in "${segment}"`);
    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);
    if (start > end) throw new RangeError(`Range start > end in "${segment}"`);
    return range(start, end);
  }

  if (segment.includes(",")) {
    const values = segment.split(",").map(s => {
      const v = parseInt(s.trim(), 10);
      if (isNaN(v)) throw new SyntaxError(`Invalid value "${s}" in list "${segment}"`);
      assertInRange(v, min, max, segment);
      return v;
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid value "${segment}"`);
  assertInRange(value, min, max, segment);
  return [value];
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length} in "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  return {
    minute:     parseSegment(minuteField, FIELD_CONFIGS[0]),
    hour:       parseSegment(hourField,   FIELD_CONFIGS[1]),
    dayOfMonth: parseSegment(domField,    FIELD_CONFIGS[2]),
    month:      parseSegment(monthField,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseSegment(dowField,    FIELD_CONFIGS[4]),
  };
};

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const range = (from: number, to: number): number[] => {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
};

const parseSegment = (segment: string, field: CronField): number[] => {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${segment}"`);
    }

    const full = base === "*" ? range(min, max) : parseSegment(base, field);
    return full.filter((v) => (v - full[0]) % step === 0);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = clamp(parseInt(fromStr, 10), min, max);
    const to   = clamp(parseInt(toStr,   10), min, max);
    return range(from, to);
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Unrecognised cron token "${segment}"`);
  }

  return [clamp(value, min, max)];
};

const parseField = (expression: string, field: CronField): number[] => {
  const values = expression
    .split(",")
    .flatMap((segment) => parseSegment(segment.trim(), field));

  // Deduplicate and sort
  return [...new Set(values)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
};

export default parseCron;

type PlainObject = Record<string, unknown>;
type FlattenedObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: PlainObject,
  prefix: string,
  result: FlattenedObject,
  seen: WeakSet<object>
): void {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  for (const key of keys) {
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      flattenObjectInternal(value, fullKey, result, seen);
    } else {
      // Leaf: primitives, arrays, Dates, RegExps, Functions, null,
      // undefined, and empty plain objects all land here as-is.
      result[fullKey] = value;
    }
  }

  // Remove after processing so the same object reference appearing in
  // sibling branches (shared, non-circular) does not trigger a false positive.
  seen.delete(obj);
}

function flattenObject(obj: PlainObject): FlattenedObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlattenedObject = {};
  flattenObjectInternal(obj, "", result, new WeakSet());
  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      result[key] = Object.prototype.hasOwnProperty.call(target, key)
        ? deepMerge(target[key], source[key])
        : source[key];
    }

    return result;
  }

  return source === undefined ? target : source;
}

export default deepMerge;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  readonly name: string;
}

const FIELD_CONFIGS = [
  { min: 0,  max: 59, name: "minute"     },
  { min: 0,  max: 23, name: "hour"       },
  { min: 1,  max: 31, name: "dayOfMonth" },
  { min: 1,  max: 12, name: "month"      },
  { min: 0,  max: 6,  name: "dayOfWeek"  },
] as const satisfies readonly FieldConfig[];

const DIGITS_RE = /^\d+$/;

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${config.min}-${config.max}] ` +
      `for field "${config.name}" in "${context}"`
    );
  }
}

function parseAtom(segment: string, config: FieldConfig): number[] {
  // Wildcard: *
  if (segment === "*") {
    return Array.from({ length: config.max - config.min + 1 }, (_, i) => config.min + i);
  }

  // Step value: base/step where base is *, a number, or a range
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const baseStr = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);

    if (stepStr === "" || !DIGITS_RE.test(stepStr)) {
      throw new SyntaxError(
        `Invalid step "${stepStr}" in field "${config.name}" segment "${segment}"`
      );
    }

    const step = parseInt(stepStr, 10);
    if (step === 0) {
      throw new RangeError(
        `Step cannot be zero in field "${config.name}" segment "${segment}"`
      );
    }

    let rangeMin: number;
    let rangeMax: number;

    if (baseStr === "*") {
      rangeMin = config.min;
      rangeMax = config.max;
    } else if (baseStr.includes("-")) {
      [rangeMin, rangeMax] = parseRangeBounds(baseStr, config);
    } else {
      if (!DIGITS_RE.test(baseStr)) {
        throw new SyntaxError(
          `Invalid base "${baseStr}" in field "${config.name}" segment "${segment}"`
        );
      }
      rangeMin = parseInt(baseStr, 10);
      rangeMax = config.max;
      assertInRange(rangeMin, config, segment);
    }

    const result: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      result.push(v);
    }
    return result;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [start, end] = parseRangeBounds(segment, config);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single integer
  if (!DIGITS_RE.test(segment)) {
    throw new SyntaxError(
      `Invalid token "${segment}" in field "${config.name}": expected a number, ` +
      `wildcard, range, or step expression`
    );
  }
  const value = parseInt(segment, 10);
  assertInRange(value, config, segment);
  return [value];
}

function parseRangeBounds(rangeStr: string, config: FieldConfig): [number, number] {
  const dashIdx = rangeStr.indexOf("-");
  const startStr = rangeStr.slice(0, dashIdx);
  const endStr   = rangeStr.slice(dashIdx + 1);

  if (!DIGITS_RE.test(startStr) || !DIGITS_RE.test(endStr)) {
    throw new SyntaxError(
      `Invalid range "${rangeStr}" in field "${config.name}": ` +
      `both bounds must be non-negative integers`
    );
  }

  const start = parseInt(startStr, 10);
  const end   = parseInt(endStr,   10);

  assertInRange(start, config, rangeStr);
  assertInRange(end,   config, rangeStr);

  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must not exceed end (${end}) ` +
      `in field "${config.name}" range "${rangeStr}"`
    );
  }

  return [start, end];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw === "" || raw.trim() !== raw) {
    throw new SyntaxError(
      `Field "${config.name}" must not be empty or contain whitespace, got "${raw}"`
    );
  }

  // Comma-separated list — split first, then parse each atom independently
  const segments = raw.split(",");

  if (segments.some(s => s === "")) {
    throw new SyntaxError(
      `Empty segment in comma list for field "${config.name}": "${raw}"`
    );
  }

  const merged = segments.flatMap(s => parseAtom(s, config));

  // Deduplicate and sort ascending — duplicates can arise from overlapping list entries
  return [...new Set(merged)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields separated by whitespace, ` +
      `got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const deepMerge = <T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S => {
  const output = { ...target } as PlainObject;

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = output[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else {
      output[key] = sourceVal;
    }
  }

  return output as T & S;
};

export default deepMerge;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step value in "${segment}" for field "${field}"`);

    const base =
      rangePart === "*"
        ? range(min, max)
        : (() => {
            const [a, b] = rangePart.split("-").map(Number);
            if (isNaN(a) || isNaN(b)) throw new TypeError(`Invalid range part "${rangePart}" for field "${field}"`);
            assertInRange(a, min, max, field);
            assertInRange(b, min, max, field);
            return range(a, b);
          })();

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new TypeError(`Invalid range "${segment}" for field "${field}"`);
    const [a, b] = parts.map(Number);
    if (isNaN(a) || isNaN(b)) throw new TypeError(`Invalid range "${segment}" for field "${field}"`);
    assertInRange(a, min, max, field);
    assertInRange(b, min, max, field);
    return range(a, b);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Literal number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new TypeError(`Invalid value "${segment}" for field "${field}"`);
  assertInRange(n, min, max, field);
  return [n];
}

function parseField(expression: string, min: number, max: number, field: string): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new TypeError(`Empty segment in field "${field}"`);
    for (const v of parseSegment(trimmed, min, max, field)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") throw new TypeError("Cron expression must be a string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new RangeError(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute, fields[0]),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour, fields[1]),
    dayOfMonth: parseField(domExpr, ...FIELD_RANGES.dayOfMonth, fields[2]),
    month: parseField(monthExpr, ...FIELD_RANGES.month, fields[3]),
    dayOfWeek: parseField(dowExpr, ...FIELD_RANGES.dayOfWeek, fields[4]),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      assertInRange(start, min, max, field);
      assertInRange(end, min, max, field);
      base = range(start, end);
    } else {
      const start = parseInt(rangePart, 10);
      assertInRange(start, min, max, field);
      base = range(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new TypeError(`Invalid range "${segment}" in field "${field}"`);
    }

    assertInRange(start, min, max, field);
    assertInRange(end, min, max, field);

    return range(start, end);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").map((s) => {
      const v = parseInt(s.trim(), 10);
      if (isNaN(v)) throw new TypeError(`Invalid value "${s}" in field "${field}"`);
      assertInRange(v, min, max, field);
      return v;
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");

  if (segments.length > 1 && segments.every((s) => !s.includes(","))) {
    // Already split by comma above; re-check if any segment is itself a list (shouldn't happen)
    const values = segments.flatMap((seg) => parseSegment(seg.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  return parseSegment(expression.trim(), field);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new RangeError(
      `Expected 5 fields in cron expression, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : String(index);
        if (item !== null && typeof item === "object" && !Array.isArray(item)) {
          flattenObject(item as NestedObject, key, result);
        } else if (Array.isArray(item)) {
          flattenObject(item as unknown as NestedObject, key, result);
        } else {
          result[key] = item as Primitive;
        }
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value === null || value === undefined) {
      result[newKey] = value;
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else if (typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type FlattenedObject = Record<string, Primitive>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  for (const [key, value] of Object.entries(obj)) {
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, flatKey, result);
    } else {
      result[flatKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start: number;
    let end: number;

    if (base === "*") {
      start = min;
      end = max;
    } else if (base.includes("-")) {
      const [s, e] = base.split("-").map(Number);
      assertInRange(s, min, max, field);
      assertInRange(e, min, max, field);
      start = s;
      end = e;
    } else {
      start = parseInt(base, 10);
      assertInRange(start, min, max, field);
      end = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const [start, end] = parts.map(Number);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Non-numeric range "${segment}" in field "${field}"`);
    }
    assertInRange(start, min, max, field);
    assertInRange(end, min, max, field);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const v of parseSegment(trimmed, field)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return isPlainObject(source) ? { ...source } : isPlainObject(target) ? { ...target } : {};
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(val: unknown): val is PlainObject {
  if (val === null || typeof val !== "object") return false;
  const proto = Object.getPrototypeOf(val);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: PlainObject,
  source: PlainObject,
  visiting: WeakSet<PlainObject>
): PlainObject {
  if (visiting.has(source)) {
    // Circular reference in source — break the cycle with a shallow copy
    return { ...source };
  }

  visiting.add(source);

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const srcVal = source[key];

    // Explicit undefined in source: skip rather than silently clobber
    if (srcVal === undefined) {
      continue;
    }

    const tgtVal = result[key];

    if (Array.isArray(srcVal) && Array.isArray(tgtVal)) {
      // Concatenate: target entries first, source entries appended
      result[key] = [...tgtVal, ...srcVal];
    } else if (isPlainObject(srcVal) && isPlainObject(tgtVal)) {
      // Both plain objects: recurse
      result[key] = mergeInternal(tgtVal, srcVal, visiting);
    } else {
      // All other cases: source wins
      result[key] = srcVal;
    }
  }

  visiting.delete(source);

  return result;
}

export default function deepMerge(
  target: PlainObject,
  source: PlainObject
): PlainObject {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: expected a plain object for 'target', got ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: expected a plain object for 'source', got ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInternal(target, source, new WeakSet());
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const range = (from: number, to: number): number[] =>
  Array.from({ length: to - from + 1 }, (_, i) => from + i);

const clamp = (value: number, min: number, max: number): number =>
  Math.min(Math.max(value, min), max);

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${segment}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        start = parseInt(startStr, 10);
        end = parseInt(endStr, 10);
      } else {
        start = parseInt(rangePart, 10);
      }
    }

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid step expression: "${segment}"`);
    }

    start = clamp(start, min, max);
    end = clamp(end, min, max);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${segment}"`);
    }
    if (start > end) {
      throw new Error(`Range start exceeds end: "${segment}"`);
    }
    if (start < min || end > max) {
      throw new Error(`Range "${segment}" out of bounds [${min}, ${max}]`);
    }

    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);

  if (isNaN(value)) {
    throw new Error(`Invalid value: "${segment}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
  }

  return [value];
};

const parseField = (field: string, config: FieldConfig): number[] => {
  const segments = field.split(",");
  const collected = segments.flatMap(seg => parseSegment(seg.trim(), config));

  // Normalize dayOfWeek: 7 (Sunday) → 0
  const normalized = collected.map(v =>
    config === FIELD_CONFIGS.dayOfWeek && v === 7 ? 0 : v
  );

  return [...new Set(normalized)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const keys = Object.keys(FIELD_CONFIGS) as (keyof CronResult)[];

  return {
    minute:     parseField(minuteField, FIELD_CONFIGS.minute),
    hour:       parseField(hourField,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domField,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthField,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowField,    FIELD_CONFIGS.dayOfWeek),
  };
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const path = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, path, result);
    } else {
      result[path] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flatten(
  obj: NestedObject | Array<unknown>,
  prefix: string,
  result: FlatObject
): void {
  if (Array.isArray(obj)) {
    obj.forEach((item, index) => {
      const key = `${prefix}[${index}]`;
      if (item !== null && typeof item === "object") {
        flatten(item as NestedObject, key, result);
      } else {
        result[key] = item as Primitive;
      }
    });
  } else {
    for (const [k, value] of Object.entries(obj)) {
      const key = prefix ? `${prefix}.${k}` : k;
      if (value !== null && typeof value === "object") {
        flatten(value as NestedObject, key, result);
      } else {
        result[key] = value as Primitive;
      }
    }
  }
}

export default function flattenObject(
  obj: NestedObject,
  prefix = ""
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    return {};
  }
  const result: FlatObject = {};
  flatten(obj, prefix, result);
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {};
    }
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

