  dayOfWeek:  { min: 0,  max: 7  },
};

const range = (from: number, to: number): number[] =>
  Array.from({ length: to - from + 1 }, (_, i) => from + i);

const assertInRange = (value: number, min: number, max: number, context: string): void => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
};

const parseSegment = (segment: string, config: FieldConfig, fieldName: string): number[] => {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step on wildcard: */n
  const stepWildcard = /^\*\/(\d+)$/.exec(segment);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);
    const values: number[] = [];
    for (let v = min; v <= max; v += step) values.push(v);
    return values;
  }

  // Step on range: n-m/s
  const stepRange = /^(\d+)-(\d+)\/(\d+)$/.exec(segment);
  if (stepRange) {
    const [, rawFrom, rawTo, rawStep] = stepRange;
    const from = parseInt(rawFrom, 10);
    const to   = parseInt(rawTo,   10);
    const step = parseInt(rawStep, 10);
    assertInRange(from, min, max, fieldName);
    assertInRange(to,   min, max, fieldName);
    if (from > to) throw new RangeError(`Range start ${from} exceeds end ${to} in field "${fieldName}"`);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);
    const values: number[] = [];
    for (let v = from; v <= to; v += step) values.push(v);
    return values;
  }

  // Range: n-m
  const simpleRange = /^(\d+)-(\d+)$/.exec(segment);
  if (simpleRange) {
    const from = parseInt(simpleRange[1], 10);
    const to   = parseInt(simpleRange[2], 10);
    assertInRange(from, min, max, fieldName);
    assertInRange(to,   min, max, fieldName);
    if (from > to) throw new RangeError(`Range start ${from} exceeds end ${to} in field "${fieldName}"`);
    return range(from, to);
  }

  // Bare number
  if (/^\d+$/.test(segment)) {
    const value = parseInt(segment, 10);
    assertInRange(value, min, max, fieldName);
    return [value];
  }

  throw new SyntaxError(`Unrecognised cron segment "${segment}" in field "${fieldName}"`);
};

const parseField = (expression: string, config: FieldConfig, fieldName: string): number[] => {
  const segments = expression.split(",");
  if (segments.length === 0) throw new SyntaxError(`Empty field "${fieldName}"`);

  const rawValues = segments.flatMap(segment => parseSegment(segment.trim(), config, fieldName));

  // Normalise dayOfWeek: both 0 and 7 represent Sunday — map 7 → 0
  const normalised = fieldName === "dayOfWeek"
    ? rawValues.map(v => (v === 7 ? 0 : v))
    : rawValues;

  return [...new Set(normalised)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but received ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute:     parseField(minuteExpr,     FIELD_CONFIGS.minute,     "minute"),
    hour:       parseField(hourExpr,       FIELD_CONFIGS.hour,       "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, FIELD_CONFIGS.dayOfMonth, "dayOfMonth"),
    month:      parseField(monthExpr,      FIELD_CONFIGS.month,      "month"),
    dayOfWeek:  parseField(dayOfWeekExpr,  FIELD_CONFIGS.dayOfWeek,  "dayOfWeek"),
  };
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive | unknown[] | Date | RegExp };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  seen = new Set<object>()
): FlatObject {
  if (!isPlainObject(input)) {
    return prefix ? { [prefix]: input } : {};
  }

  if (seen.has(input)) {
    console.warn(`flattenObject: circular reference detected at key "${prefix}", skipping`);
    return {};
  }

  seen.add(input);

  const result: FlatObject = {};
  const keys = Object.keys(input);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {};
    }
    seen.delete(input);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const value = input[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const nested = flattenObject(value, newKey, seen);
      Object.assign(result, nested);
    } else {
      result[newKey] = value as Primitive | unknown[] | Date | RegExp;
    }
  }

  seen.delete(input);
  return result;
}

export default flattenObject;
